// ============== STORAGE SHIM ==============
// Falls back to localStorage when running outside Claude.ai (where window.storage doesn't exist)
if (typeof window !== 'undefined' && !window.storage) {
  window.storage = {
    get: async (key) => {
      try {
        const value = localStorage.getItem(key);
        if (value === null) throw new Error('not found');
        return { value };
      } catch (e) {
        throw e;
      }
    },
    set: async (key, value) => {
      localStorage.setItem(key, value);
      return { value };
    },
    delete: async (key) => {
      localStorage.removeItem(key);
      return { deleted: true };
    },
    list: async (prefix) => {
      const keys = [];
      for (let i = 0; i < localStorage.length; i++) {
        const k = localStorage.key(i);
        if (!prefix || k.startsWith(prefix)) keys.push(k);
      }
      return { keys };
    }
  };
}

const CUSTOM_FONT_BASE64 = "";

const FONT_FAMILY = '"PingHL", "Heebo", system-ui, sans-serif';

function FontStyles() {
  return (
    <style dangerouslySetInnerHTML={{ __html: `
      @font-face {
        font-family: 'PingHL';
        src: url(data:font/woff2;base64,${CUSTOM_FONT_BASE64}) format('woff2');
        font-weight: normal;
        font-style: normal;
        font-display: swap;
      }
      body, html, input, textarea, select, button {
        font-family: ${FONT_FAMILY} !important;
      }
    `}} />
  );
}

