// ============== CLIENT POST MODAL (with approval) ==============
function ClientPostModal({ post, onClose, onApprove, onReject, onSendMessage, onEditMessage, onDeleteMessage, currentUserName }) {
  const [showCommentBox, setShowCommentBox] = useState(false);
  const [actionType, setActionType] = useState(null);
  const [comment, setComment] = useState('');

  const handleStartAction = (type) => {
    setActionType(type);
    setShowCommentBox(true);
    setComment(post.clientApproval?.comment || '');
  };

  const handleSubmit = () => {
    if (actionType === 'reject' && !comment.trim()) {
      alert('יש להוסיף הערה לבקשת שינוי');
      return;
    }
    if (actionType === 'approve') {
      onApprove(comment);
    } else {
      onReject(comment);
    }
    setShowCommentBox(false);
    setActionType(null);
    setComment('');
  };

  const currentStatus = post.clientApproval?.status;
  const isPending = !currentStatus;

  return (
    <div className="fixed inset-0 bg-slate-900/50 flex items-end sm:items-center justify-center z-50 sm:p-4 backdrop-blur-sm" onClick={onClose}>
      <div className="bg-white rounded-t-2xl sm:rounded-2xl max-w-2xl w-full max-h-[95vh] sm:max-h-[90vh] overflow-y-auto" onClick={(e) => e.stopPropagation()}>
        <div className="sticky top-0 bg-white border-b border-slate-200 px-6 py-4 flex items-center justify-between z-10">
          <h2 className="text-lg font-bold text-slate-900">
            {isPending ? '⏳ פוסט ממתין לאישורך' : currentStatus === 'approved' ? '✓ פוסט אושר' : '⚠ פוסט דורש שינוי'}
          </h2>
          <button onClick={onClose} className="p-1.5 hover:bg-slate-100 rounded-lg">
            <X className="w-5 h-5 text-slate-500" />
          </button>
        </div>

        {/* Status Banner - very prominent at top */}
        {currentStatus && !showCommentBox && (
          <div className={`px-6 py-4 border-b ${
            currentStatus === 'approved' 
              ? 'bg-emerald-50 border-emerald-200' 
              : 'bg-rose-50 border-rose-200'
          }`}>
            <div className="flex items-start gap-3">
              <div className={`w-10 h-10 rounded-full flex items-center justify-center flex-shrink-0 ${
                currentStatus === 'approved' ? 'bg-emerald-500' : 'bg-rose-500'
              }`}>
                {currentStatus === 'approved' 
                  ? <CheckCircle className="w-6 h-6 text-white" />
                  : <XCircle className="w-6 h-6 text-white" />}
              </div>
              <div className="flex-1">
                <h3 className={`font-bold text-base ${currentStatus === 'approved' ? 'text-emerald-900' : 'text-rose-900'}`}>
                  {currentStatus === 'approved' ? 'הפוסט אושר על ידך!' : 'ביקשת שינוי בפוסט'}
                </h3>
                <p className={`text-sm mt-0.5 ${currentStatus === 'approved' ? 'text-emerald-700' : 'text-rose-700'}`}>
                  {currentStatus === 'approved' 
                    ? 'הצוות יקבל התראה ויפרסם את הפוסט בתאריך המתוזמן'
                    : 'הצוות יקבל את ההערה ויעדכן את הפוסט'}
                </p>
                {post.clientApproval.comment && (
                  <div className="mt-2 px-3 py-2 bg-white/70 rounded-lg text-sm">
                    <MessageSquare className="w-3.5 h-3.5 inline ml-1" />
                    <span className="font-semibold">ההערה שלך: </span>
                    {post.clientApproval.comment}
                  </div>
                )}
              </div>
            </div>
          </div>
        )}

        {/* Pending notice */}
        {isPending && !showCommentBox && (
          <div className="px-6 py-3 bg-amber-50 border-b border-amber-200 flex items-center gap-2">
            <AlertCircle className="w-4 h-4 text-amber-600 flex-shrink-0" />
            <p className="text-sm text-amber-800">
              נא לעבור על הפוסט ולאשר או לבקש שינוי בכפתורים בתחתית
            </p>
          </div>
        )}

        <div className="p-6 space-y-4">
          <div className="flex items-center gap-4 text-sm text-slate-600 flex-wrap">
            <div className="flex items-center gap-1.5">
              <Calendar className="w-4 h-4" />
              {formatDateHebrew(post.date)}
            </div>
            {post.time && (
              <div className="flex items-center gap-1.5">
                <Clock className="w-4 h-4" />
                {post.time}
              </div>
            )}
          </div>

          {post.title && <h3 className="text-xl font-bold text-slate-900">{post.title}</h3>}

          <div className="text-slate-700 leading-relaxed bg-slate-50 rounded-lg p-4 border border-slate-100" dangerouslySetInnerHTML={{ __html: post.content }} />

          {post.mediaData && (
            <div className="rounded-xl overflow-hidden bg-slate-100">
              {post.mediaType === 'image' ? (
                <img src={post.mediaData} alt="" className="w-full" />
              ) : (
                <video src={post.mediaData} controls className="w-full" />
              )}
            </div>
          )}

          {/* Comment Box */}
          {showCommentBox && (
            <div className={`border-2 rounded-lg p-4 ${
              actionType === 'approve' ? 'border-emerald-300 bg-emerald-50' : 'border-rose-300 bg-rose-50'
            }`}>
              <label className="block text-sm font-semibold text-slate-800 mb-2">
                {actionType === 'approve' ? '✓ אישור פוסט - הערה (אופציונלי)' : '⚠ מה תרצה לשנות בפוסט?'}
              </label>
              <textarea
                value={comment}
                onChange={(e) => setComment(e.target.value)}
                rows={3}
                placeholder={actionType === 'approve' ? 'הוסף הערה לצוות (לא חובה)...' : 'נא לתאר בפירוט מה דרוש לשנות'}
                className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500 resize-none bg-white"
                autoFocus
              />
              <div className="flex gap-2 mt-3 justify-end">
                <button onClick={() => { setShowCommentBox(false); setComment(''); }} className="px-4 py-2 text-sm text-slate-700 hover:bg-white rounded-lg">ביטול</button>
                <button
                  onClick={handleSubmit}
                  className={`px-5 py-2 text-sm text-white font-semibold rounded-lg shadow-sm ${
                    actionType === 'approve' ? 'bg-emerald-600 hover:bg-emerald-700' : 'bg-rose-600 hover:bg-rose-700'
                  }`}
                >
                  {actionType === 'approve' ? '✓ אישור סופי' : '⚠ שלח בקשת שינוי'}
                </button>
              </div>
            </div>
          )}

          {/* Chat */}
          {onSendMessage && (
            <PostChat
              messages={post.messages || []}
              onSendMessage={onSendMessage}
              onEditMessage={onEditMessage}
              onDeleteMessage={onDeleteMessage}
              currentUserRole="client"
              currentUserName={currentUserName || 'לקוח'}
            />
          )}
        </div>

        {/* Action buttons - LARGE and PROMINENT */}
        {!showCommentBox && (
          <div className="sticky bottom-0 bg-white border-t-2 border-slate-200 px-6 py-4 shadow-lg">
            <div className="flex items-center gap-3">
              <button
                onClick={() => handleStartAction('reject')}
                className={`flex-1 py-4 text-base font-bold rounded-xl transition-all flex items-center justify-center gap-2 shadow-sm ${
                  currentStatus === 'rejected'
                    ? 'bg-rose-100 text-rose-700 border-2 border-rose-400'
                    : 'bg-white border-2 border-rose-300 text-rose-700 hover:bg-rose-50 hover:border-rose-500 hover:shadow-md'
                }`}
              >
                <XCircle className="w-5 h-5" />
                {currentStatus === 'rejected' ? 'ביקשת שינוי ✓' : 'בקש שינוי'}
              </button>
              <button
                onClick={() => handleStartAction('approve')}
                className={`flex-1 py-4 text-base font-bold rounded-xl transition-all flex items-center justify-center gap-2 shadow-sm ${
                  currentStatus === 'approved'
                    ? 'bg-emerald-100 text-emerald-700 border-2 border-emerald-400'
                    : 'bg-emerald-600 hover:bg-emerald-700 text-white border-2 border-emerald-600 hover:shadow-lg'
                }`}
              >
                <CheckCircle className="w-5 h-5" />
                {currentStatus === 'approved' ? 'אושר על ידך ✓' : 'אשר פוסט'}
              </button>
            </div>
            {isPending && (
              <p className="text-xs text-center text-slate-500 mt-2">
                לחץ על אחד הכפתורים כדי לאשר או לבקש שינוי
              </p>
            )}
          </div>
        )}
      </div>
    </div>
  );
}

// ============== POST CHAT ==============
function PostChat({ messages = [], onSendMessage, onEditMessage, onDeleteMessage, currentUserRole, currentUserName }) {
  const [newMessage, setNewMessage] = useState('');
  const [editingId, setEditingId] = useState(null);
  const [editingText, setEditingText] = useState('');
  const [openMenuId, setOpenMenuId] = useState(null);
  const messagesEndRef = useRef(null);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages.length]);

  // Close menu on outside click
  useEffect(() => {
    if (!openMenuId) return;
    const handler = () => setOpenMenuId(null);
    document.addEventListener('click', handler);
    return () => document.removeEventListener('click', handler);
  }, [openMenuId]);

  const handleSend = () => {
    if (!newMessage.trim()) return;
    onSendMessage({
      id: Date.now().toString(),
      author: currentUserName,
      authorRole: currentUserRole,
      text: newMessage.trim(),
      timestamp: new Date().toISOString()
    });
    setNewMessage('');
  };

  const startEdit = (msg) => {
    setEditingId(msg.id);
    setEditingText(msg.text);
    setOpenMenuId(null);
  };

  const cancelEdit = () => {
    setEditingId(null);
    setEditingText('');
  };

  const saveEdit = () => {
    if (!editingText.trim()) {
      alert('הודעה לא יכולה להיות ריקה');
      return;
    }
    if (onEditMessage) {
      onEditMessage(editingId, editingText.trim());
    }
    setEditingId(null);
    setEditingText('');
  };

  const handleDelete = (msgId) => {
    if (!confirm('האם למחוק את ההודעה?')) return;
    if (onDeleteMessage) {
      onDeleteMessage(msgId);
    }
    setOpenMenuId(null);
  };

  const formatTime = (iso) => {
    const d = new Date(iso);
    const today = new Date();
    const isToday = d.toDateString() === today.toDateString();
    if (isToday) {
      return d.toLocaleTimeString('he-IL', { hour: '2-digit', minute: '2-digit' });
    }
    return d.toLocaleDateString('he-IL', { day: '2-digit', month: '2-digit', hour: '2-digit', minute: '2-digit' });
  };

  return (
    <div className="border border-slate-200 rounded-lg overflow-hidden bg-slate-50">
      <div className="bg-white border-b border-slate-200 px-3 py-2 flex items-center gap-2">
        <MessageCircle className="w-4 h-4 text-slate-600" />
        <span className="text-sm font-semibold text-slate-900">שיחה</span>
        <span className="text-xs text-slate-500">({messages.length} הודעות)</span>
      </div>
      
      <div className="max-h-64 overflow-y-auto p-3 space-y-2">
        {messages.length === 0 ? (
          <div className="text-center py-6 text-slate-400 text-sm">
            אין עדיין הודעות. תוכל להתחיל שיחה על הפוסט.
          </div>
        ) : (
          messages.map(msg => {
            const isMine = msg.authorRole === currentUserRole;
            const isAdmin = msg.authorRole === 'admin';
            const isEditing = editingId === msg.id;
            const menuOpen = openMenuId === msg.id;
            
            return (
              <div key={msg.id} className={`flex ${isMine ? 'justify-start' : 'justify-end'}`}>
                <div className={`relative group max-w-[80%] rounded-lg p-2 ${
                  isAdmin 
                    ? 'bg-indigo-100 border border-indigo-200' 
                    : 'bg-white border border-slate-200'
                }`}>
                  <div className="flex items-center gap-2 mb-1">
                    <span className={`text-xs font-semibold ${isAdmin ? 'text-indigo-700' : 'text-slate-700'}`}>
                      {msg.author}
                    </span>
                    <span className="text-xs text-slate-400">{formatTime(msg.timestamp)}</span>
                    {msg.editedAt && (
                      <span className="text-xs text-slate-400 italic">(נערך)</span>
                    )}
                    
                    {/* Menu button - only shown for own messages */}
                    {isMine && !isEditing && (
                      <div className="relative mr-auto">
                        <button
                          onClick={(e) => {
                            e.stopPropagation();
                            setOpenMenuId(menuOpen ? null : msg.id);
                          }}
                          className="p-0.5 hover:bg-black/10 rounded transition opacity-60 hover:opacity-100"
                          title="אפשרויות"
                        >
                          <span className="text-xs leading-none px-1">⋯</span>
                        </button>
                        
                        {menuOpen && (
                          <div className="absolute top-full left-0 mt-1 bg-white border border-slate-200 rounded-lg shadow-lg z-30 py-1 min-w-[120px]" onClick={(e) => e.stopPropagation()}>
                            <button
                              onClick={() => startEdit(msg)}
                              className="w-full px-3 py-1.5 text-right text-xs text-slate-700 hover:bg-slate-50 flex items-center gap-2"
                            >
                              <Edit3 className="w-3 h-3" />
                              עריכה
                            </button>
                            <button
                              onClick={() => handleDelete(msg.id)}
                              className="w-full px-3 py-1.5 text-right text-xs text-rose-600 hover:bg-rose-50 flex items-center gap-2"
                            >
                              <Trash2 className="w-3 h-3" />
                              מחיקה
                            </button>
                          </div>
                        )}
                      </div>
                    )}
                  </div>
                  
                  {isEditing ? (
                    <div className="space-y-2">
                      <textarea
                        value={editingText}
                        onChange={(e) => setEditingText(e.target.value)}
                        onKeyDown={(e) => {
                          if (e.key === 'Enter' && !e.shiftKey) {
                            e.preventDefault();
                            saveEdit();
                          }
                          if (e.key === 'Escape') cancelEdit();
                        }}
                        rows={2}
                        autoFocus
                        className="w-full px-2 py-1 text-sm border border-slate-300 rounded resize-none focus:outline-none focus:ring-2 focus:ring-indigo-500 bg-white"
                      />
                      <div className="flex gap-1 justify-end">
                        <button
                          onClick={cancelEdit}
                          className="px-2 py-1 text-xs text-slate-600 hover:bg-slate-200 rounded"
                        >
                          ביטול
                        </button>
                        <button
                          onClick={saveEdit}
                          className="px-2 py-1 text-xs bg-indigo-600 hover:bg-indigo-700 text-white rounded"
                        >
                          שמור
                        </button>
                      </div>
                    </div>
                  ) : (
                    <p className="text-sm text-slate-800 whitespace-pre-wrap">{msg.text}</p>
                  )}
                </div>
              </div>
            );
          })
        )}
        <div ref={messagesEndRef} />
      </div>

      <div className="bg-white border-t border-slate-200 p-2 flex gap-2">
        <input
          type="text"
          value={newMessage}
          onChange={(e) => setNewMessage(e.target.value)}
          onKeyDown={(e) => e.key === 'Enter' && handleSend()}
          placeholder="הקלד הודעה..."
          className="flex-1 px-3 py-1.5 text-sm border border-slate-200 rounded-md focus:outline-none focus:ring-2 focus:ring-indigo-500"
        />
        <button
          onClick={handleSend}
          disabled={!newMessage.trim()}
          className="px-3 py-1.5 bg-indigo-600 hover:bg-indigo-700 disabled:bg-slate-300 text-white text-sm font-medium rounded-md flex items-center gap-1"
        >
          <Send className="w-3.5 h-3.5" />
          שלח
        </button>
      </div>
    </div>
  );
}

// ============== HISTORY VIEW ==============
function HistoryView({ history = [] }) {
  if (history.length === 0) {
    return (
      <div className="text-center py-4 text-slate-400 text-sm">
        אין עדיין שינויים מתועדים
      </div>
    );
  }

  const formatDate = (iso) => {
    const d = new Date(iso);
    return d.toLocaleDateString('he-IL', { day: '2-digit', month: '2-digit', year: 'numeric', hour: '2-digit', minute: '2-digit' });
  };

  return (
    <div className="border border-slate-200 rounded-lg overflow-hidden bg-slate-50">
      <div className="bg-white border-b border-slate-200 px-3 py-2 flex items-center gap-2">
        <History className="w-4 h-4 text-slate-600" />
        <span className="text-sm font-semibold text-slate-900">היסטוריית שינויים</span>
        <span className="text-xs text-slate-500">({history.length})</span>
      </div>
      <div className="max-h-48 overflow-y-auto p-2 space-y-1">
        {[...history].reverse().map((entry, idx) => (
          <div key={idx} className="bg-white rounded p-2 text-xs border border-slate-100">
            <div className="flex items-center justify-between mb-0.5">
              <span className="font-semibold text-slate-700">{entry.action}</span>
              <span className="text-slate-400">{formatDate(entry.timestamp)}</span>
            </div>
            <div className="text-slate-600">
              <span className="font-medium">{entry.author}</span>
              {entry.details && <span className="text-slate-500"> · {entry.details}</span>}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

