// ============== CALENDAR VIEW ==============
function CalendarView({ currentMonth, setCurrentMonth, posts, onPostClick, getBusinessColor }) {
  const [viewType, setViewType] = useState('month'); // 'day', 'week', 'month'
  const [currentDate, setCurrentDate] = useState(currentMonth);
  
  const months = ['ינואר', 'פברואר', 'מרץ', 'אפריל', 'מאי', 'יוני', 'יולי', 'אוגוסט', 'ספטמבר', 'אוקטובר', 'נובמבר', 'דצמבר'];
  const dayNames = ['א', 'ב', 'ג', 'ד', 'ה', 'ו', 'ש'];
  const dayNamesLong = ['ראשון', 'שני', 'שלישי', 'רביעי', 'חמישי', 'שישי', 'שבת'];

  const formatDateKey = (d) => {
    const year = d.getFullYear();
    const month = String(d.getMonth() + 1).padStart(2, '0');
    const day = String(d.getDate()).padStart(2, '0');
    return `${year}-${month}-${day}`;
  };

  const postsByDate = posts.reduce((acc, post) => {
    if (!acc[post.date]) acc[post.date] = [];
    acc[post.date].push(post);
    return acc;
  }, {});

  // Sync currentMonth with currentDate
  useEffect(() => {
    setCurrentMonth(currentDate);
  }, [currentDate, setCurrentMonth]);

  // Navigation helpers
  const navigatePrevious = () => {
    const d = new Date(currentDate);
    if (viewType === 'day') d.setDate(d.getDate() - 1);
    else if (viewType === 'week') d.setDate(d.getDate() - 7);
    else d.setMonth(d.getMonth() - 1);
    setCurrentDate(d);
  };

  const navigateNext = () => {
    const d = new Date(currentDate);
    if (viewType === 'day') d.setDate(d.getDate() + 1);
    else if (viewType === 'week') d.setDate(d.getDate() + 7);
    else d.setMonth(d.getMonth() + 1);
    setCurrentDate(d);
  };

  const goToToday = () => setCurrentDate(new Date());

  const changeYear = (delta) => {
    const d = new Date(currentDate);
    d.setFullYear(d.getFullYear() + delta);
    setCurrentDate(d);
  };

  // Title based on view
  const getTitle = () => {
    if (viewType === 'day') {
      return `יום ${dayNamesLong[currentDate.getDay()]}, ${currentDate.getDate()} ב${months[currentDate.getMonth()]} ${currentDate.getFullYear()}`;
    }
    if (viewType === 'week') {
      const weekStart = new Date(currentDate);
      weekStart.setDate(currentDate.getDate() - currentDate.getDay());
      const weekEnd = new Date(weekStart);
      weekEnd.setDate(weekStart.getDate() + 6);
      const sameMonth = weekStart.getMonth() === weekEnd.getMonth();
      if (sameMonth) {
        return `${weekStart.getDate()}-${weekEnd.getDate()} ב${months[weekStart.getMonth()]} ${weekStart.getFullYear()}`;
      }
      return `${weekStart.getDate()} ${months[weekStart.getMonth()]} - ${weekEnd.getDate()} ${months[weekEnd.getMonth()]} ${weekEnd.getFullYear()}`;
    }
    return `${months[currentDate.getMonth()]} ${currentDate.getFullYear()}`;
  };

  // Month grid
  const getDaysInMonth = (date) => {
    const year = date.getFullYear();
    const month = date.getMonth();
    const firstDay = new Date(year, month, 1);
    const lastDay = new Date(year, month + 1, 0);
    const daysInMonth = lastDay.getDate();
    const startingDayOfWeek = firstDay.getDay();

    const days = [];
    for (let i = 0; i < startingDayOfWeek; i++) days.push(null);
    for (let day = 1; day <= daysInMonth; day++) days.push(new Date(year, month, day));
    return days;
  };

  // Week days  
  const getWeekDays = (date) => {
    const start = new Date(date);
    start.setDate(date.getDate() - date.getDay());
    const days = [];
    for (let i = 0; i < 7; i++) {
      const d = new Date(start);
      d.setDate(start.getDate() + i);
      days.push(d);
    }
    return days;
  };

  return (
    <div className="bg-white rounded-xl border border-slate-200 overflow-hidden">
      {/* Header with navigation */}
      <div className="px-5 py-4 border-b border-slate-200">
        <div className="flex items-center justify-between flex-wrap gap-3">
          <div className="flex items-center gap-3">
            <h3 className="font-semibold text-slate-900 text-base min-w-fit">{getTitle()}</h3>
          </div>

          <div className="flex items-center gap-2 flex-wrap">
            {/* View Type Tabs */}
            <div className="flex bg-slate-100 rounded-lg p-1">
              <button
                onClick={() => setViewType('day')}
                className={`px-3 py-1 text-sm rounded-md transition ${viewType === 'day' ? 'bg-white shadow-sm text-slate-900 font-medium' : 'text-slate-600'}`}
              >
                יום
              </button>
              <button
                onClick={() => setViewType('week')}
                className={`px-3 py-1 text-sm rounded-md transition ${viewType === 'week' ? 'bg-white shadow-sm text-slate-900 font-medium' : 'text-slate-600'}`}
              >
                שבוע
              </button>
              <button
                onClick={() => setViewType('month')}
                className={`px-3 py-1 text-sm rounded-md transition ${viewType === 'month' ? 'bg-white shadow-sm text-slate-900 font-medium' : 'text-slate-600'}`}
              >
                חודש
              </button>
            </div>

            {/* Year Navigation */}
            <div className="flex items-center gap-1 border border-slate-200 rounded-lg p-1">
              <button
                onClick={() => changeYear(-1)}
                className="p-1 hover:bg-slate-100 rounded transition"
                title="שנה קודמת"
              >
                <ChevronRight className="w-3.5 h-3.5 text-slate-600" />
              </button>
              <span className="text-xs font-medium text-slate-700 px-1 min-w-[3rem] text-center">{currentDate.getFullYear()}</span>
              <button
                onClick={() => changeYear(1)}
                className="p-1 hover:bg-slate-100 rounded transition"
                title="שנה הבאה"
              >
                <ChevronLeft className="w-3.5 h-3.5 text-slate-600" />
              </button>
            </div>

            {/* Period Navigation */}
            <div className="flex items-center gap-1">
              <button
                onClick={navigatePrevious}
                className="p-1.5 hover:bg-slate-100 rounded-lg transition"
                title={viewType === 'day' ? 'יום קודם' : viewType === 'week' ? 'שבוע קודם' : 'חודש קודם'}
              >
                <ChevronRight className="w-4 h-4 text-slate-600" />
              </button>
              <button onClick={goToToday} className="px-3 py-1.5 text-xs hover:bg-slate-100 rounded-lg font-medium">היום</button>
              <button
                onClick={navigateNext}
                className="p-1.5 hover:bg-slate-100 rounded-lg transition"
                title={viewType === 'day' ? 'יום הבא' : viewType === 'week' ? 'שבוע הבא' : 'חודש הבא'}
              >
                <ChevronLeft className="w-4 h-4 text-slate-600" />
              </button>
            </div>
          </div>
        </div>
      </div>

      {/* Day View */}
      {viewType === 'day' && (
        <DayView 
          date={currentDate}
          posts={postsByDate[formatDateKey(currentDate)] || []}
          onPostClick={onPostClick}
          getBusinessColor={getBusinessColor}
        />
      )}

      {/* Week View */}
      {viewType === 'week' && (
        <WeekView 
          weekDays={getWeekDays(currentDate)}
          postsByDate={postsByDate}
          formatDateKey={formatDateKey}
          onPostClick={onPostClick}
          getBusinessColor={getBusinessColor}
          dayNames={dayNames}
          onDayClick={(d) => { setCurrentDate(d); setViewType('day'); }}
        />
      )}

      {/* Month View */}
      {viewType === 'month' && (
        <MonthView
          days={getDaysInMonth(currentDate)}
          postsByDate={postsByDate}
          formatDateKey={formatDateKey}
          onPostClick={onPostClick}
          getBusinessColor={getBusinessColor}
          dayNames={dayNames}
          onDayClick={(d) => { setCurrentDate(d); setViewType('day'); }}
        />
      )}
    </div>
  );
}

// Day View
function DayView({ date, posts, onPostClick, getBusinessColor }) {
  const isToday = date.toDateString() === new Date().toDateString();
  const sortedPosts = [...posts].sort((a, b) => {
    const timeA = a.time || '00:00';
    const timeB = b.time || '00:00';
    return timeA.localeCompare(timeB);
  });

  return (
    <div className="p-5">
      {sortedPosts.length === 0 ? (
        <div className="text-center py-16">
          <Calendar className="w-12 h-12 text-slate-300 mx-auto mb-3" />
          <p className="text-slate-500 text-sm">אין פוסטים מתוזמנים ליום זה</p>
        </div>
      ) : (
        <div className="space-y-3">
          {sortedPosts.map(post => (
            <button
              key={post.id}
              onClick={() => onPostClick(post)}
              className="w-full text-right bg-white border border-slate-200 hover:border-slate-300 hover:shadow-sm rounded-lg p-4 transition flex items-start gap-4"
            >
              <div className="flex-shrink-0 flex flex-col items-center gap-1">
                <div className={`w-3 h-3 rounded-full ${getBusinessColor(post.businessName)}`}></div>
                {post.time && (
                  <span className="text-xs font-mono text-slate-600 bg-slate-100 px-1.5 py-0.5 rounded">{post.time}</span>
                )}
              </div>
              <div className="flex-1 min-w-0">
                <div className="font-semibold text-slate-900 text-sm mb-0.5">{post.businessName}</div>
                {post.title && <div className="text-sm text-slate-700 mb-1">{post.title}</div>}
                <div className="text-xs text-slate-500 line-clamp-2">{stripHtml(post.content)}</div>
              </div>
              {post.mediaData && (
                <div className="flex-shrink-0">
                  {post.mediaType === 'image' ? (
                    <img src={post.mediaData} alt="" className="w-16 h-16 object-cover rounded-lg" />
                  ) : (
                    <div className="w-16 h-16 bg-slate-900 rounded-lg flex items-center justify-center">
                      <Video className="w-5 h-5 text-white" />
                    </div>
                  )}
                </div>
              )}
            </button>
          ))}
        </div>
      )}
    </div>
  );
}

// Week View
function WeekView({ weekDays, postsByDate, formatDateKey, onPostClick, getBusinessColor, dayNames, onDayClick }) {
  const today = new Date().toDateString();
  
  return (
    <>
      {/* Day headers */}
      <div className="grid grid-cols-7 border-b border-slate-200 bg-slate-50">
        {weekDays.map((day, idx) => {
          const isToday = day.toDateString() === today;
          return (
            <button
              key={idx}
              onClick={() => onDayClick(day)}
              className={`px-2 py-3 text-center transition hover:bg-slate-100 ${isToday ? 'bg-indigo-50' : ''}`}
            >
              <div className="text-xs text-slate-500">{dayNames[day.getDay()]}</div>
              <div className={`text-lg font-semibold mt-0.5 ${isToday ? 'text-indigo-600' : 'text-slate-700'}`}>
                {day.getDate()}
              </div>
            </button>
          );
        })}
      </div>

      {/* Day columns */}
      <div className="grid grid-cols-7 min-h-[400px]">
        {weekDays.map((day, idx) => {
          const dateKey = formatDateKey(day);
          const dayPosts = (postsByDate[dateKey] || []).sort((a, b) => 
            (a.time || '00:00').localeCompare(b.time || '00:00')
          );
          const isToday = day.toDateString() === today;
          
          return (
            <div
              key={idx}
              className={`border-l border-slate-100 p-2 ${isToday ? 'bg-indigo-50/30' : ''} ${idx === 6 ? '' : ''}`}
            >
              <div className="space-y-1.5">
                {dayPosts.map(post => (
                  <button
                    key={post.id}
                    onClick={() => onPostClick(post)}
                    className={`w-full text-right text-xs p-1.5 rounded-md text-white ${getBusinessColor(post.businessName)} hover:opacity-90 transition`}
                    title={post.title || stripHtml(post.content)}
                  >
                    {post.time && <div className="text-[10px] opacity-90 font-mono">{post.time}</div>}
                    <div className="font-medium truncate">{post.businessName}</div>
                    {post.title && <div className="text-[10px] opacity-90 truncate mt-0.5">{post.title}</div>}
                  </button>
                ))}
              </div>
            </div>
          );
        })}
      </div>
    </>
  );
}

// Month View
function MonthView({ days, postsByDate, formatDateKey, onPostClick, getBusinessColor, dayNames, onDayClick }) {
  const today = formatDateKey(new Date());

  return (
    <>
      <div className="grid grid-cols-7 border-b border-slate-200 bg-slate-50">
        {dayNames.map(day => (
          <div key={day} className="px-2 py-2 text-center text-xs font-semibold text-slate-600">{day}</div>
        ))}
      </div>

      <div className="grid grid-cols-7">
        {days.map((day, idx) => {
          if (!day) return <div key={idx} className="min-h-[110px] border-b border-l border-slate-100 bg-slate-50/50"></div>;
          const dateKey = formatDateKey(day);
          const dayPosts = postsByDate[dateKey] || [];
          const isToday = today === dateKey;

          return (
            <div
              key={idx}
              className={`min-h-[110px] border-b border-l border-slate-100 p-1.5 ${isToday ? 'bg-indigo-50/50' : 'hover:bg-slate-50/50'} transition cursor-pointer`}
              onClick={() => onDayClick(day)}
            >
              <div className={`text-xs font-medium mb-1 ${isToday ? 'text-indigo-600' : 'text-slate-700'}`}>{day.getDate()}</div>
              <div className="space-y-1">
                {dayPosts.slice(0, 3).map(post => (
                  <button
                    key={post.id}
                    onClick={(e) => { e.stopPropagation(); onPostClick(post); }}
                    className={`w-full text-right text-xs px-1.5 py-1 rounded text-white truncate ${getBusinessColor(post.businessName)} hover:opacity-90 transition`}
                    title={post.title || stripHtml(post.content)}
                  >
                    {post.businessName}
                  </button>
                ))}
                {dayPosts.length > 3 && <div className="text-xs text-slate-500 px-1">+{dayPosts.length - 3} עוד</div>}
              </div>
            </div>
          );
        })}
      </div>
    </>
  );
}

// ============== GANTT VIEW ==============
function GanttView({ posts, businesses, onPostClick, getBusinessColor }) {
  const [viewMonth, setViewMonth] = useState(new Date());
  
  const monthNames = ['ינואר', 'פברואר', 'מרץ', 'אפריל', 'מאי', 'יוני', 'יולי', 'אוגוסט', 'ספטמבר', 'אוקטובר', 'נובמבר', 'דצמבר'];
  const dayNames = ['א', 'ב', 'ג', 'ד', 'ה', 'ו', 'ש'];
  
  // Calculate first and last day of the current month
  const year = viewMonth.getFullYear();
  const month = viewMonth.getMonth();
  const firstDay = new Date(year, month, 1);
  const lastDay = new Date(year, month + 1, 0);
  const daysInMonth = lastDay.getDate();
  
  const dayList = [];
  for (let i = 0; i < daysInMonth; i++) {
    dayList.push(new Date(year, month, i + 1));
  }
  
  const dayMs = 24 * 60 * 60 * 1000;
  const today = new Date();
  today.setHours(0, 0, 0, 0);
  
  // Filter posts to current month only
  const monthPosts = posts.filter(p => {
    const d = new Date(p.date);
    return d.getFullYear() === year && d.getMonth() === month;
  });
  
  const postsByBusiness = businesses.reduce((acc, biz) => {
    acc[biz] = monthPosts.filter(p => p.businessName === biz);
    return acc;
  }, {});
  
  // Count of posts visible (in current month)
  const visibleCount = monthPosts.length;
  
  // Navigation
  const goToPreviousMonth = () => setViewMonth(new Date(year, month - 1, 1));
  const goToNextMonth = () => setViewMonth(new Date(year, month + 1, 1));
  const goToToday = () => setViewMonth(new Date());
  
  const dayWidth = 100;
  const cardHeight = 90;
  
  // Get platform info
  const getPlatformIcons = (platforms) => {
    if (!platforms || platforms.length === 0) return null;
    return platforms.slice(0, 3).map(pid => {
      const p = PLATFORMS.find(pl => pl.id === pid);
      return p ? p.icon : '';
    });
  };
  
  // Get status border color
  const getStatusStyle = (post) => {
    const approval = post.clientApproval;
    if (approval?.status === 'approved') {
      return { borderColor: '#10b981', borderWidth: '2px' };
    }
    if (approval?.status === 'rejected') {
      return { borderColor: '#f43f5e', borderWidth: '2px' };
    }
    return { borderColor: '#e2e8f0', borderWidth: '1px' };
  };

  return (
    <div className="bg-white rounded-xl border border-slate-200 overflow-hidden">
      {/* Header with month navigation */}
      <div className="px-5 py-4 border-b border-slate-200 flex items-center justify-between flex-wrap gap-3">
        <div className="flex items-center gap-3">
          <h3 className="text-lg font-bold text-slate-900">
            {monthNames[month]} {year}
          </h3>
          <span className="text-xs text-slate-500 px-2 py-1 bg-slate-100 rounded-md">
            {visibleCount} פוסטים · {businesses.length} עסקים
          </span>
        </div>
        
        <div className="flex items-center gap-1">
          <button 
            onClick={goToPreviousMonth}
            className="p-1.5 hover:bg-slate-100 rounded-lg transition"
            title="חודש קודם"
          >
            <ChevronRight className="w-4 h-4 text-slate-600" />
          </button>
          <button 
            onClick={goToToday}
            className="px-3 py-1.5 text-sm text-slate-700 hover:bg-slate-100 rounded-lg font-medium"
          >
            היום
          </button>
          <button 
            onClick={goToNextMonth}
            className="p-1.5 hover:bg-slate-100 rounded-lg transition"
            title="חודש הבא"
          >
            <ChevronLeft className="w-4 h-4 text-slate-600" />
          </button>
        </div>
      </div>

      {/* Empty state */}
      {businesses.length === 0 ? (
        <div className="p-12 text-center text-slate-500">
          <BarChart3 className="w-12 h-12 mx-auto mb-3 text-slate-300" />
          <p className="text-sm">אין עסקים להצגה</p>
        </div>
      ) : visibleCount === 0 ? (
        <div className="p-12 text-center text-slate-500">
          <Calendar className="w-12 h-12 mx-auto mb-3 text-slate-300" />
          <p className="text-sm">אין פוסטים בחודש זה</p>
          <p className="text-xs text-slate-400 mt-1">השתמש בחיצים כדי לעבור לחודש אחר</p>
        </div>
      ) : (
        <div className="overflow-x-auto">
          <div style={{ minWidth: `${220 + daysInMonth * dayWidth}px` }}>
            {/* Days header */}
            <div className="flex border-b-2 border-slate-200 bg-gradient-to-b from-slate-50 to-white sticky top-0 z-10">
              <div className="w-[220px] flex-shrink-0 px-4 py-3 border-l border-slate-200 font-semibold text-sm text-slate-700 bg-white">
                עסק
              </div>
              <div className="flex">
                {dayList.map((day, idx) => {
                  const isToday = day.getTime() === today.getTime();
                  const isWeekend = day.getDay() === 5 || day.getDay() === 6;
                  return (
                    <div 
                      key={idx} 
                      style={{ width: `${dayWidth}px` }} 
                      className={`flex-shrink-0 px-2 py-3 text-center border-l border-slate-200 ${
                        isToday ? 'bg-indigo-50' : isWeekend ? 'bg-slate-50/50' : ''
                      }`}
                    >
                      <div className={`text-xs ${isToday ? 'text-indigo-600 font-semibold' : 'text-slate-500'}`}>
                        {dayNames[day.getDay()]}
                      </div>
                      <div className={`text-lg font-bold mt-0.5 ${
                        isToday ? 'text-indigo-700' : 'text-slate-700'
                      }`}>
                        {day.getDate()}
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>

            {/* Business rows */}
            {businesses.map((biz, bizIdx) => {
              const bizPosts = postsByBusiness[biz];
              
              return (
                <div 
                  key={biz} 
                  className={`flex border-b border-slate-100 hover:bg-slate-50/30 transition relative ${
                    bizIdx % 2 === 0 ? '' : 'bg-slate-50/20'
                  }`}
                  style={{ minHeight: `${cardHeight + 16}px` }}
                >
                  {/* Business name (sticky) */}
                  <div className="w-[220px] flex-shrink-0 px-4 py-3 border-l border-slate-200 flex items-center gap-2.5 sticky right-0 bg-white z-[5] shadow-sm">
                    <div className={`w-3 h-3 rounded-full ${getBusinessColor(biz)} flex-shrink-0`}></div>
                    <div className="flex-1 min-w-0">
                      <div className="font-semibold text-sm text-slate-900 truncate">{biz}</div>
                      <div className="text-xs text-slate-500 mt-0.5">
                        {bizPosts.length} פוסטים
                      </div>
                    </div>
                  </div>
                  
                  {/* Day cells background */}
                  <div className="flex relative">
                    {dayList.map((day, idx) => {
                      const isToday = day.getTime() === today.getTime();
                      const isWeekend = day.getDay() === 5 || day.getDay() === 6;
                      return (
                        <div 
                          key={idx} 
                          style={{ width: `${dayWidth}px` }} 
                          className={`flex-shrink-0 border-l border-slate-100 ${
                            isToday ? 'bg-indigo-50/40' : isWeekend ? 'bg-slate-50/30' : ''
                          }`}
                        ></div>
                      );
                    })}

                    {/* Posts positioned absolutely */}
                    {bizPosts.map((post) => {
                      const postDate = new Date(post.date);
                      postDate.setHours(0, 0, 0, 0);
                      const dayInMonth = postDate.getDate();
                      const daysDiff = dayInMonth - 1; // 0-indexed
                      const leftPos = daysDiff * dayWidth + 4;
                      const cardWidth = dayWidth - 8;
                      
                      const approval = post.clientApproval;
                      const statusStyle = getStatusStyle(post);
                      const platformIcons = getPlatformIcons(post.platforms);
                      const category = POST_CATEGORIES[post.category] || POST_CATEGORIES.content;
                      
                      // Truncate content for display
                      const displayContent = post.title || stripHtml(post.content || '').substring(0, 40);
                      
                      return (
                        <button
                          key={post.id}
                          onClick={() => onPostClick(post)}
                          style={{ 
                            right: `${leftPos}px`, 
                            width: `${cardWidth}px`, 
                            top: '8px',
                            height: `${cardHeight}px`,
                            ...statusStyle,
                            borderStyle: 'solid'
                          }}
                          className="absolute bg-white rounded-lg overflow-hidden hover:shadow-md transition group cursor-pointer text-right"
                          title={`${post.title || ''}\n${stripHtml(post.content)}`}
                        >
                          {/* Status indicator strip on top */}
                          <div 
                            className={`absolute top-0 right-0 left-0 h-1 ${getBusinessColor(biz)}`}
                          ></div>
                          
                          {/* Approval badge top-left */}
                          {approval && (
                            <div className={`absolute top-1.5 left-1.5 w-4 h-4 rounded-full flex items-center justify-center z-10 ${
                              approval.status === 'approved' ? 'bg-emerald-500' : 'bg-rose-500'
                            }`}>
                              {approval.status === 'approved' 
                                ? <CheckCircle className="w-3 h-3 text-white" />
                                : <XCircle className="w-3 h-3 text-white" />
                              }
                            </div>
                          )}
                          
                          {/* Media preview */}
                          {post.mediaData ? (
                            <div className="h-12 w-full overflow-hidden bg-slate-100 mt-1">
                              {post.mediaType === 'image' ? (
                                <img 
                                  src={post.mediaData} 
                                  alt="" 
                                  className="w-full h-full object-cover"
                                />
                              ) : (
                                <div className="w-full h-full bg-slate-900 flex items-center justify-center relative">
                                  <video src={post.mediaData} className="w-full h-full object-cover absolute inset-0" />
                                  <Video className="w-4 h-4 text-white relative z-10" />
                                </div>
                              )}
                            </div>
                          ) : (
                            <div className="h-12 w-full bg-slate-50 mt-1 flex items-center justify-center">
                              <span className="text-base">{category.icon}</span>
                            </div>
                          )}
                          
                          {/* Content area */}
                          <div className="px-1.5 py-1">
                            <div className="text-xs font-medium text-slate-900 truncate leading-tight">
                              {displayContent || 'ללא כותרת'}
                            </div>
                            <div className="flex items-center justify-between mt-0.5">
                              {post.time && (
                                <span className="text-[10px] text-slate-500 font-mono">{post.time}</span>
                              )}
                              {platformIcons && (
                                <div className="flex items-center gap-0.5 text-[10px] text-slate-600">
                                  {platformIcons.map((icon, i) => (
                                    <span key={i}>{icon}</span>
                                  ))}
                                </div>
                              )}
                            </div>
                          </div>
                        </button>
                      );
                    })}
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      )}
      
      {/* Legend */}
      <div className="px-5 py-3 border-t border-slate-200 bg-slate-50/50 flex items-center gap-4 text-xs text-slate-600 flex-wrap">
        <div className="flex items-center gap-1.5">
          <div className="w-3 h-3 rounded border-2 border-emerald-500 bg-white"></div>
          <span>אושר</span>
        </div>
        <div className="flex items-center gap-1.5">
          <div className="w-3 h-3 rounded border-2 border-rose-500 bg-white"></div>
          <span>דורש שינוי</span>
        </div>
        <div className="flex items-center gap-1.5">
          <div className="w-3 h-3 rounded border border-slate-300 bg-white"></div>
          <span>ממתין לאישור</span>
        </div>
        <div className="text-slate-400 mr-auto">לחץ על פוסט לפרטים מלאים</div>
      </div>
    </div>
  );
}

// ============== BRANDING SETTINGS ==============
function BrandingSettings({ branding, updateBranding }) {
  const [formData, setFormData] = useState(branding);
  const [saved, setSaved] = useState(false);
  const logoInputRef = useRef(null);

  const handleLogoUpload = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    if (file.size > 2 * 1024 * 1024) {
      alert('הקובץ גדול מדי. עד 2MB');
      return;
    }
    const reader = new FileReader();
    reader.onload = (event) => {
      setFormData({ ...formData, logoData: event.target.result });
    };
    reader.readAsDataURL(file);
  };

  const handleSave = async () => {
    await updateBranding(formData);
    setSaved(true);
    setTimeout(() => setSaved(false), 2500);
  };

  const handleReset = async () => {
    if (!confirm('לאפס את כל הגדרות המיתוג לברירת המחדל?')) return;
    setFormData(DEFAULT_BRANDING);
    await updateBranding(DEFAULT_BRANDING);
  };

  const presetColors = [
    { name: 'אינדיגו', primary: '#4f46e5', secondary: '#9333ea' },
    { name: 'כחול', primary: '#2563eb', secondary: '#0891b2' },
    { name: 'ירוק', primary: '#059669', secondary: '#0d9488' },
    { name: 'ורוד', primary: '#db2777', secondary: '#e11d48' },
    { name: 'כתום', primary: '#ea580c', secondary: '#d97706' },
    { name: 'אדום', primary: '#dc2626', secondary: '#b91c1c' },
    { name: 'סגול', primary: '#7c3aed', secondary: '#a855f7' },
    { name: 'שחור', primary: '#1f2937', secondary: '#374151' },
  ];

  return (
    <div className="max-w-4xl space-y-6">
      <div className="bg-white rounded-xl border border-slate-200 overflow-hidden">
        <div className="px-6 py-4 border-b border-slate-200 bg-slate-50">
          <h2 className="font-semibold text-slate-900">מיתוג המערכת</h2>
          <p className="text-xs text-slate-500 mt-0.5">התאם את המראה של המערכת לעסק שלך - השינויים יחולו עבור כל המשתמשים</p>
        </div>

        <div className="p-6 space-y-6">
          {/* Theme Selector */}
          <div>
            <label className="block text-sm font-medium text-slate-700 mb-2">סגנון מערכת</label>
            <div className="grid grid-cols-2 gap-2">
              <button
                onClick={() => setFormData({ ...formData, theme: 'light' })}
                className={`p-3 rounded-lg border-2 transition text-right ${
                  formData.theme === 'light' ? 'border-slate-900' : 'border-slate-200 hover:border-slate-300'
                }`}
              >
                <div className="flex items-center justify-between mb-2">
                  <span className="text-sm font-medium text-slate-900">בהיר</span>
                  {formData.theme === 'light' && <CheckCircle className="w-4 h-4 text-slate-900" />}
                </div>
                <div className="h-12 rounded bg-gradient-to-br from-slate-50 to-white border border-slate-200 flex items-center justify-center">
                  <div className="w-6 h-6 rounded bg-slate-200"></div>
                </div>
              </button>
              <button
                onClick={() => setFormData({ ...formData, theme: 'dark' })}
                className={`p-3 rounded-lg border-2 transition text-right ${
                  formData.theme === 'dark' ? 'border-slate-900' : 'border-slate-200 hover:border-slate-300'
                }`}
              >
                <div className="flex items-center justify-between mb-2">
                  <span className="text-sm font-medium text-slate-900">כהה</span>
                  {formData.theme === 'dark' && <CheckCircle className="w-4 h-4 text-slate-900" />}
                </div>
                <div className="h-12 rounded bg-gradient-to-br from-slate-900 to-slate-800 border border-slate-700 flex items-center justify-center">
                  <div className="w-6 h-6 rounded" style={{ backgroundColor: formData.secondaryColor }}></div>
                </div>
              </button>
            </div>
          </div>

          {/* Logo */}
          <div>
            <label className="block text-sm font-medium text-slate-700 mb-2">לוגו</label>
            <div className="flex items-center gap-4">
              {formData.logoData ? (
                <div className={`w-24 h-24 rounded-2xl border-2 p-2 flex-shrink-0 ${
                  formData.theme === 'dark' ? 'bg-slate-900 border-slate-700' : 'bg-white border-slate-200'
                }`}>
                  <img src={formData.logoData} alt="logo" className="w-full h-full object-contain" />
                </div>
              ) : (
                <div 
                  className="w-24 h-24 rounded-2xl flex items-center justify-center flex-shrink-0"
                  style={{ background: `linear-gradient(135deg, ${formData.primaryColor}, ${formData.secondaryColor})` }}
                >
                  <Calendar className="w-10 h-10 text-white" />
                </div>
              )}
              <div className="flex-1">
                <div className="flex gap-2 mb-2">
                  <button
                    onClick={() => logoInputRef.current?.click()}
                    className="px-3 py-1.5 text-sm bg-white border border-slate-200 rounded-lg hover:bg-slate-50 transition flex items-center gap-1.5"
                  >
                    <Upload className="w-4 h-4" />
                    {formData.logoData ? 'החלף לוגו' : 'העלה לוגו'}
                  </button>
                  {formData.logoData && (
                    <button
                      onClick={() => setFormData({ ...formData, logoData: null })}
                      className="px-3 py-1.5 text-sm text-red-600 border border-red-200 rounded-lg hover:bg-red-50 transition flex items-center gap-1.5"
                    >
                      <Trash2 className="w-4 h-4" />
                      הסר
                    </button>
                  )}
                </div>
                <p className="text-xs text-slate-500">PNG, JPG או SVG · רצוי רקע שקוף · עד 2MB</p>
              </div>
              <input ref={logoInputRef} type="file" accept="image/*" onChange={handleLogoUpload} className="hidden" />
            </div>
          </div>

          {/* Company Name */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1.5">שם החברה / המערכת</label>
              <input
                type="text"
                value={formData.companyName}
                onChange={(e) => setFormData({ ...formData, companyName: e.target.value })}
                placeholder="לוח תוכן"
                className="w-full px-3 py-2 border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500"
              />
              <p className="text-xs text-slate-500 mt-1">יוצג בכותרת המערכת ובמסך ההתחברות</p>
            </div>

            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1.5">תיאור / טאגליין</label>
              <input
                type="text"
                value={formData.tagline}
                onChange={(e) => setFormData({ ...formData, tagline: e.target.value })}
                placeholder="מערכת ניהול ואישור תוכן"
                className="w-full px-3 py-2 border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500"
              />
              <p className="text-xs text-slate-500 mt-1">יוצג מתחת לשם במסך ההתחברות</p>
            </div>

            <div className="md:col-span-2">
              <label className="block text-sm font-medium text-slate-700 mb-1.5">כותרת מסך כניסה</label>
              <input
                type="text"
                value={formData.loginWelcome}
                onChange={(e) => setFormData({ ...formData, loginWelcome: e.target.value })}
                placeholder="כניסה למערכת"
                className="w-full px-3 py-2 border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500"
              />
            </div>
          </div>

          {/* Color Presets */}
          <div>
            <label className="block text-sm font-medium text-slate-700 mb-2">סכמת צבעים</label>
            <div className="grid grid-cols-4 md:grid-cols-8 gap-2 mb-4">
              {presetColors.map(preset => (
                <button
                  key={preset.name}
                  onClick={() => setFormData({ ...formData, primaryColor: preset.primary, secondaryColor: preset.secondary })}
                  className={`relative aspect-square rounded-xl overflow-hidden border-2 transition ${
                    formData.primaryColor === preset.primary ? 'border-slate-900 scale-105' : 'border-transparent hover:border-slate-300'
                  }`}
                  style={{ background: `linear-gradient(135deg, ${preset.primary}, ${preset.secondary})` }}
                  title={preset.name}
                >
                  {formData.primaryColor === preset.primary && (
                    <div className="absolute inset-0 flex items-center justify-center">
                      <CheckCircle className="w-5 h-5 text-white drop-shadow-md" />
                    </div>
                  )}
                </button>
              ))}
            </div>

            {/* Custom Colors */}
            <div className="grid grid-cols-2 gap-3">
              <div>
                <label className="block text-xs font-medium text-slate-600 mb-1">צבע ראשי</label>
                <div className="flex gap-2">
                  <input
                    type="color"
                    value={formData.primaryColor}
                    onChange={(e) => setFormData({ ...formData, primaryColor: e.target.value })}
                    className="w-10 h-10 rounded-lg border border-slate-200 cursor-pointer"
                  />
                  <input
                    type="text"
                    value={formData.primaryColor}
                    onChange={(e) => setFormData({ ...formData, primaryColor: e.target.value })}
                    className="flex-1 px-3 py-2 border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500 font-mono text-sm"
                    dir="ltr"
                  />
                </div>
              </div>
              <div>
                <label className="block text-xs font-medium text-slate-600 mb-1">צבע משני</label>
                <div className="flex gap-2">
                  <input
                    type="color"
                    value={formData.secondaryColor}
                    onChange={(e) => setFormData({ ...formData, secondaryColor: e.target.value })}
                    className="w-10 h-10 rounded-lg border border-slate-200 cursor-pointer"
                  />
                  <input
                    type="text"
                    value={formData.secondaryColor}
                    onChange={(e) => setFormData({ ...formData, secondaryColor: e.target.value })}
                    className="flex-1 px-3 py-2 border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500 font-mono text-sm"
                    dir="ltr"
                  />
                </div>
              </div>
            </div>
          </div>

          {/* Preview */}
          <div>
            <label className="block text-sm font-medium text-slate-700 mb-2">תצוגה מקדימה</label>
            <div 
              className="rounded-xl p-6 border border-slate-200"
              style={{ 
                background: formData.theme === 'dark' 
                  ? `linear-gradient(135deg, #0a0a0a, ${formData.secondaryColor}15)` 
                  : `linear-gradient(135deg, ${formData.primaryColor}08, ${formData.secondaryColor}08)` 
              }}
            >
              <div className={`rounded-xl p-5 shadow-sm max-w-sm mx-auto ${
                formData.theme === 'dark' ? 'bg-slate-900 border border-slate-800' : 'bg-white border border-slate-100'
              }`}>
                <div className="flex flex-col items-center text-center">
                  {formData.logoData ? (
                    <div className={`w-20 h-20 rounded-2xl overflow-hidden p-1.5 mb-3 ${
                      formData.theme === 'dark' ? 'bg-slate-900' : 'bg-white border border-slate-100'
                    }`}>
                      <img src={formData.logoData} alt="logo" className="w-full h-full object-contain" />
                    </div>
                  ) : (
                    <div 
                      className="w-12 h-12 rounded-xl flex items-center justify-center mb-3"
                      style={{ background: `linear-gradient(135deg, ${formData.primaryColor}, ${formData.secondaryColor})` }}
                    >
                      <Calendar className="w-6 h-6 text-white" />
                    </div>
                  )}
                  <h3 className={`font-bold mb-0.5 ${formData.theme === 'dark' ? 'text-white' : 'text-slate-900'}`}>{formData.companyName || 'שם החברה'}</h3>
                  <p className={`text-xs mb-4 ${formData.theme === 'dark' ? 'text-slate-400' : 'text-slate-500'}`}>{formData.tagline || 'תיאור'}</p>
                  <button
                    type="button"
                    className="w-full py-2 text-sm font-medium rounded-lg"
                    style={{ 
                      backgroundColor: formData.theme === 'dark' ? formData.secondaryColor : formData.primaryColor,
                      color: formData.theme === 'dark' ? '#0a0a0a' : '#ffffff'
                    }}
                  >
                    כניסה
                  </button>
                </div>
              </div>
            </div>
          </div>
        </div>

        <div className="px-6 py-4 border-t border-slate-200 bg-slate-50 flex items-center justify-between">
          <button
            onClick={handleReset}
            className="px-4 py-2 text-sm text-slate-700 hover:bg-white rounded-lg transition"
          >
            איפוס לברירת מחדל
          </button>
          <div className="flex items-center gap-3">
            {saved && (
              <span className="text-sm text-emerald-600 font-medium flex items-center gap-1.5">
                <CheckCircle className="w-4 h-4" /> נשמר בהצלחה
              </span>
            )}
            <button
              onClick={handleSave}
              className="px-5 py-2 text-white text-sm font-medium rounded-lg transition hover:opacity-90"
              style={{ backgroundColor: formData.primaryColor }}
            >
              שמור שינויים
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

// ============== TEAM CHAT (between admins) ==============
function TeamChat({ currentUser, allUsers }) {
  const [messages, setMessages] = useState([]);
  const [newMessage, setNewMessage] = useState('');
  const [isCollapsed, setIsCollapsed] = useState(false);
  const [editingId, setEditingId] = useState(null);
  const [editingText, setEditingText] = useState('');
  const [openMenuId, setOpenMenuId] = useState(null);
  const [lastReadAt, setLastReadAt] = useState(null);
  const messagesEndRef = useRef(null);
  const messagesContainerRef = useRef(null);

  // Get only admins (the team)
  const teamMembers = allUsers.filter(u => u.role === 'admin');

  // Color palette for users (consistent per user)
  const userColors = [
    { bg: 'bg-indigo-100', text: 'text-indigo-700', border: 'border-indigo-200' },
    { bg: 'bg-emerald-100', text: 'text-emerald-700', border: 'border-emerald-200' },
    { bg: 'bg-amber-100', text: 'text-amber-700', border: 'border-amber-200' },
    { bg: 'bg-purple-100', text: 'text-purple-700', border: 'border-purple-200' },
    { bg: 'bg-rose-100', text: 'text-rose-700', border: 'border-rose-200' },
    { bg: 'bg-cyan-100', text: 'text-cyan-700', border: 'border-cyan-200' },
  ];

  const getUserColor = (username) => {
    // Hash username to consistent color
    let hash = 0;
    for (let i = 0; i < username.length; i++) {
      hash = ((hash << 5) - hash) + username.charCodeAt(i);
      hash |= 0;
    }
    return userColors[Math.abs(hash) % userColors.length];
  };

  // Load messages and last-read time
  useEffect(() => {
    loadMessages();
    loadLastRead();
  }, []);

  const loadMessages = async () => {
    try {
      const result = await window.storage.get('team-chat');
      if (result && result.value) {
        setMessages(JSON.parse(result.value));
      }
    } catch (e) {
      // No messages yet
    }
  };

  const loadLastRead = async () => {
    try {
      const result = await window.storage.get(`team-chat-read-${currentUser.username}`);
      if (result && result.value) {
        setLastReadAt(JSON.parse(result.value));
      }
    } catch (e) {}
  };

  const saveMessages = async (updated) => {
    setMessages(updated);
    await window.storage.set('team-chat', JSON.stringify(updated));
  };

  const markAllRead = async () => {
    const now = new Date().toISOString();
    setLastReadAt(now);
    await window.storage.set(`team-chat-read-${currentUser.username}`, JSON.stringify(now));
  };

  // Auto-scroll to bottom on new messages
  useEffect(() => {
    if (!isCollapsed) {
      messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
      // Mark as read after a short delay
      const timer = setTimeout(markAllRead, 1000);
      return () => clearTimeout(timer);
    }
  }, [messages.length, isCollapsed]);

  // Close menu on outside click
  useEffect(() => {
    if (!openMenuId) return;
    const handler = () => setOpenMenuId(null);
    document.addEventListener('click', handler);
    return () => document.removeEventListener('click', handler);
  }, [openMenuId]);

  const handleSend = () => {
    if (!newMessage.trim()) return;
    const message = {
      id: Date.now().toString() + Math.random().toString(36).substr(2, 5),
      author: currentUser.name || currentUser.username,
      authorUsername: currentUser.username,
      text: newMessage.trim(),
      timestamp: new Date().toISOString()
    };
    saveMessages([...messages, message]);
    setNewMessage('');
  };

  const startEdit = (msg) => {
    setEditingId(msg.id);
    setEditingText(msg.text);
    setOpenMenuId(null);
  };

  const cancelEdit = () => {
    setEditingId(null);
    setEditingText('');
  };

  const saveEdit = async () => {
    if (!editingText.trim()) {
      alert('הודעה לא יכולה להיות ריקה');
      return;
    }
    const updated = messages.map(m => 
      m.id === editingId 
        ? { ...m, text: editingText.trim(), editedAt: new Date().toISOString() }
        : m
    );
    await saveMessages(updated);
    setEditingId(null);
    setEditingText('');
  };

  const handleDelete = async (msgId) => {
    if (!confirm('האם למחוק את ההודעה?')) return;
    const updated = messages.filter(m => m.id !== msgId);
    await saveMessages(updated);
    setOpenMenuId(null);
  };

  const formatTime = (iso) => {
    const d = new Date(iso);
    const now = new Date();
    const diffMs = now - d;
    const diffMins = Math.floor(diffMs / 60000);
    const diffHours = Math.floor(diffMs / 3600000);
    const diffDays = Math.floor(diffMs / 86400000);

    if (diffMins < 1) return 'הרגע';
    if (diffMins < 60) return `לפני ${diffMins} ד׳`;
    if (diffHours < 24 && d.toDateString() === now.toDateString()) {
      return d.toLocaleTimeString('he-IL', { hour: '2-digit', minute: '2-digit' });
    }
    if (diffDays === 1) return `אתמול ${d.toLocaleTimeString('he-IL', { hour: '2-digit', minute: '2-digit' })}`;
    if (diffDays < 7) return d.toLocaleDateString('he-IL', { weekday: 'long', hour: '2-digit', minute: '2-digit' });
    return d.toLocaleDateString('he-IL', { day: '2-digit', month: '2-digit', hour: '2-digit', minute: '2-digit' });
  };

  // Count unread messages
  const unreadCount = lastReadAt 
    ? messages.filter(m => 
        m.authorUsername !== currentUser.username && 
        new Date(m.timestamp) > new Date(lastReadAt)
      ).length
    : messages.filter(m => m.authorUsername !== currentUser.username).length;

  // Show always - even if user is alone (so they can see and test it)
  const isAlone = teamMembers.length < 2;

  return (
    <div className="bg-white rounded-xl border border-slate-200 mb-4 sm:mb-6 overflow-hidden">
      {/* Header */}
      <button
        onClick={() => setIsCollapsed(!isCollapsed)}
        className="w-full px-3 sm:px-4 py-3 flex items-center justify-between hover:bg-slate-50 transition border-b border-slate-100"
      >
        <div className="flex items-center gap-2.5">
          <div className="relative">
            <div className="w-9 h-9 bg-gradient-to-br from-indigo-500 to-purple-500 rounded-full flex items-center justify-center">
              <MessageCircle className="w-4 h-4 text-white" />
            </div>
            {unreadCount > 0 && (
              <span className="absolute -top-1 -left-1 bg-rose-500 text-white text-xs font-bold w-5 h-5 rounded-full flex items-center justify-center border-2 border-white">
                {unreadCount > 9 ? '9+' : unreadCount}
              </span>
            )}
          </div>
          <div className="text-right">
            <h3 className="text-sm font-bold text-slate-900">צ׳אט צוות</h3>
            <p className="text-xs text-slate-500">
              {isAlone 
                ? 'הוסף מנהלים נוספים כדי להתחיל לתקשר'
                : `${teamMembers.length} מנהלים · ${messages.length} הודעות`
              }
            </p>
          </div>
        </div>
        <div className="flex items-center gap-2">
          {!isCollapsed && unreadCount > 0 && (
            <span className="text-xs text-rose-600 font-medium animate-pulse">
              {unreadCount} חדשות
            </span>
          )}
          <ChevronLeft className={`w-5 h-5 text-slate-400 transition-transform ${isCollapsed ? 'rotate-90' : '-rotate-90'}`} />
        </div>
      </button>

      {/* Messages area */}
      {!isCollapsed && (
        <>
          <div ref={messagesContainerRef} className="max-h-72 overflow-y-auto p-3 bg-slate-50/50 space-y-2">
            {messages.length === 0 ? (
              <div className="text-center py-8">
                <MessageCircle className="w-10 h-10 mx-auto mb-2 text-slate-300" />
                {isAlone ? (
                  <>
                    <p className="text-sm text-slate-500">אתה היחיד במערכת כרגע</p>
                    <p className="text-xs text-slate-400 mt-1">הוסף מנהלים נוספים בלשונית "לקוחות" כדי להתחיל צ׳אט פנימי</p>
                  </>
                ) : (
                  <>
                    <p className="text-sm text-slate-500">אין עדיין הודעות</p>
                    <p className="text-xs text-slate-400 mt-1">תהיה הראשון להתחיל את השיחה</p>
                  </>
                )}
              </div>
            ) : (
              messages.map((msg, idx) => {
                const isMine = msg.authorUsername === currentUser.username;
                const userColor = getUserColor(msg.authorUsername);
                const isEditing = editingId === msg.id;
                const menuOpen = openMenuId === msg.id;
                const isNew = lastReadAt && new Date(msg.timestamp) > new Date(lastReadAt) && !isMine;
                
                // Check if previous message from same user
                const prevMsg = idx > 0 ? messages[idx - 1] : null;
                const sameAuthor = prevMsg && prevMsg.authorUsername === msg.authorUsername &&
                  (new Date(msg.timestamp) - new Date(prevMsg.timestamp)) < 5 * 60 * 1000;
                
                return (
                  <div key={msg.id} className={`flex ${isMine ? 'justify-start' : 'justify-end'} ${sameAuthor ? '' : 'mt-3'}`}>
                    <div className={`relative group max-w-[85%] sm:max-w-[75%] rounded-lg p-2 sm:p-2.5 ${
                      isMine 
                        ? 'bg-indigo-600 text-white' 
                        : `${userColor.bg} ${userColor.border} border`
                    } ${isNew ? 'ring-2 ring-rose-300 ring-offset-1' : ''}`}>
                      
                      {/* Author name (only if different from previous) */}
                      {!sameAuthor && (
                        <div className="flex items-center gap-2 mb-1">
                          <span className={`text-xs font-bold ${
                            isMine ? 'text-indigo-100' : userColor.text
                          }`}>
                            {isMine ? 'אני' : msg.author}
                          </span>
                        </div>
                      )}

                      {/* Edit mode */}
                      {isEditing ? (
                        <div className="space-y-2">
                          <textarea
                            value={editingText}
                            onChange={(e) => setEditingText(e.target.value)}
                            onKeyDown={(e) => {
                              if (e.key === 'Enter' && !e.shiftKey) {
                                e.preventDefault();
                                saveEdit();
                              }
                              if (e.key === 'Escape') cancelEdit();
                            }}
                            rows={2}
                            autoFocus
                            className="w-full px-2 py-1 text-sm text-slate-900 bg-white border border-slate-300 rounded resize-none focus:outline-none focus:ring-2 focus:ring-indigo-500"
                          />
                          <div className="flex gap-1 justify-end">
                            <button
                              onClick={cancelEdit}
                              className="px-2 py-1 text-xs bg-white/20 hover:bg-white/30 rounded text-white"
                            >
                              ביטול
                            </button>
                            <button
                              onClick={saveEdit}
                              className="px-2 py-1 text-xs bg-white text-indigo-700 rounded font-medium"
                            >
                              שמור
                            </button>
                          </div>
                        </div>
                      ) : (
                        <>
                          <p className={`text-sm whitespace-pre-wrap break-words ${
                            isMine ? 'text-white' : 'text-slate-800'
                          }`}>
                            {msg.text}
                          </p>
                          <div className="flex items-center gap-1.5 mt-1">
                            <span className={`text-xs ${isMine ? 'text-indigo-200' : 'text-slate-500'}`}>
                              {formatTime(msg.timestamp)}
                            </span>
                            {msg.editedAt && (
                              <span className={`text-xs italic ${isMine ? 'text-indigo-200' : 'text-slate-400'}`}>
                                (נערך)
                              </span>
                            )}
                          </div>
                        </>
                      )}
                      
                      {/* Menu button for own messages */}
                      {isMine && !isEditing && (
                        <div className="absolute -left-7 top-2 opacity-0 group-hover:opacity-100 transition">
                          <div className="relative">
                            <button
                              onClick={(e) => {
                                e.stopPropagation();
                                setOpenMenuId(menuOpen ? null : msg.id);
                              }}
                              className="p-1 hover:bg-slate-200 rounded transition text-slate-500"
                              title="אפשרויות"
                            >
                              <span className="text-sm leading-none px-1">⋯</span>
                            </button>
                            
                            {menuOpen && (
                              <div className="absolute top-full left-0 mt-1 bg-white border border-slate-200 rounded-lg shadow-lg z-30 py-1 min-w-[120px]" onClick={(e) => e.stopPropagation()}>
                                <button
                                  onClick={() => startEdit(msg)}
                                  className="w-full px-3 py-1.5 text-right text-xs text-slate-700 hover:bg-slate-50 flex items-center gap-2"
                                >
                                  <Edit3 className="w-3 h-3" />
                                  עריכה
                                </button>
                                <button
                                  onClick={() => handleDelete(msg.id)}
                                  className="w-full px-3 py-1.5 text-right text-xs text-rose-600 hover:bg-rose-50 flex items-center gap-2"
                                >
                                  <Trash2 className="w-3 h-3" />
                                  מחיקה
                                </button>
                              </div>
                            )}
                          </div>
                        </div>
                      )}
                    </div>
                  </div>
                );
              })
            )}
            <div ref={messagesEndRef} />
          </div>

          {/* Input area */}
          <div className="bg-white border-t border-slate-200 p-2 flex gap-2">
            <input
              type="text"
              value={newMessage}
              onChange={(e) => setNewMessage(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleSend()}
              placeholder="הודעה לצוות..."
              className="flex-1 px-3 py-2 text-sm border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500"
            />
            <button
              onClick={handleSend}
              disabled={!newMessage.trim()}
              className="px-3 py-2 bg-indigo-600 hover:bg-indigo-700 disabled:bg-slate-300 text-white text-sm font-medium rounded-lg flex items-center gap-1.5"
            >
              <Send className="w-4 h-4" />
              <span className="hidden sm:inline">שלח</span>
            </button>
          </div>
        </>
      )}
    </div>
  );
}

// ============== SMART CHARACTER COUNTER ==============
function SmartCharCounter({ content, platforms }) {
  const text = content ? stripHtml(content) : '';
  const charCount = text.length;
  
  // Find the most restrictive platform
  const selectedPlatforms = PLATFORMS.filter(p => platforms.includes(p.id));
  if (selectedPlatforms.length === 0) {
    return (
      <div className="text-xs text-slate-400 mt-1">
        {charCount} תווים
      </div>
    );
  }

  return (
    <div className="mt-2 space-y-1">
      <div className="flex flex-wrap gap-2 text-xs">
        {selectedPlatforms.map(p => {
          const percent = (charCount / p.limit) * 100;
          const isOver = charCount > p.limit;
          const isNearLimit = percent > 80 && !isOver;
          const isIdeal = charCount <= p.ideal;
          
          return (
            <div 
              key={p.id} 
              className={`px-2 py-1 rounded-md border flex items-center gap-1.5 ${
                isOver 
                  ? 'bg-rose-50 border-rose-300 text-rose-700' 
                  : isNearLimit
                  ? 'bg-amber-50 border-amber-300 text-amber-700'
                  : isIdeal
                  ? 'bg-emerald-50 border-emerald-200 text-emerald-700'
                  : 'bg-slate-50 border-slate-200 text-slate-600'
              }`}
              title={`${p.name}: מומלץ עד ${p.ideal} תווים, מקסימום ${p.limit.toLocaleString()}`}
            >
              <span className="font-medium">{p.name}:</span>
              <span className="font-mono">
                {charCount.toLocaleString()}/{p.limit.toLocaleString()}
              </span>
              {isOver && <AlertCircle className="w-3 h-3" />}
              {!isOver && isIdeal && <CheckCircle className="w-3 h-3" />}
            </div>
          );
        })}
      </div>
    </div>
  );
}

// ============== TEMPLATES MODAL ==============
function TemplatesModal({ templates, saveTemplates, currentContent, currentTitle, onSelect, onClose }) {
  const [mode, setMode] = useState('list'); // 'list' or 'save'
  const [newTemplateName, setNewTemplateName] = useState('');
  const [searchTerm, setSearchTerm] = useState('');

  const handleSave = async () => {
    if (!newTemplateName.trim()) {
      alert('יש להזין שם לתבנית');
      return;
    }
    if (!currentContent.trim()) {
      alert('אין תוכן לשמור כתבנית');
      return;
    }
    const newTemplate = {
      id: Date.now().toString(),
      name: newTemplateName.trim(),
      title: currentTitle || '',
      content: currentContent,
      createdAt: new Date().toISOString()
    };
    await saveTemplates([...templates, newTemplate]);
    setNewTemplateName('');
    setMode('list');
  };

  const handleDelete = async (id) => {
    if (!confirm('האם למחוק את התבנית?')) return;
    await saveTemplates(templates.filter(t => t.id !== id));
  };

  const filteredTemplates = templates.filter(t =>
    !searchTerm || 
    t.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    stripHtml(t.content).toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="fixed inset-0 bg-slate-900/50 flex items-end sm:items-center justify-center z-[60] sm:p-4 backdrop-blur-sm" onClick={onClose}>
      <div className="bg-white rounded-t-2xl sm:rounded-2xl max-w-2xl w-full max-h-[95vh] sm:max-h-[85vh] overflow-y-auto" onClick={(e) => e.stopPropagation()}>
        <div className="sticky top-0 bg-white border-b border-slate-200 px-6 py-4 flex items-center justify-between z-10">
          <div className="flex items-center gap-3">
            <div className="w-9 h-9 rounded-xl bg-indigo-100 flex items-center justify-center">
              <FileText className="w-4 h-4 text-indigo-600" />
            </div>
            <div>
              <h2 className="text-lg font-bold text-slate-900">תבניות פוסטים</h2>
              <p className="text-xs text-slate-500">{templates.length} תבניות שמורות</p>
            </div>
          </div>
          <button onClick={onClose} className="p-1.5 hover:bg-slate-100 rounded-lg">
            <X className="w-5 h-5 text-slate-500" />
          </button>
        </div>

        <div className="p-6">
          <div className="flex gap-2 mb-4">
            <button
              onClick={() => setMode('list')}
              className={`flex-1 py-2 px-3 text-sm rounded-lg transition ${
                mode === 'list' ? 'bg-indigo-100 text-indigo-700 font-medium' : 'bg-slate-50 text-slate-600 hover:bg-slate-100'
              }`}
            >
              טען תבנית קיימת
            </button>
            <button
              onClick={() => setMode('save')}
              className={`flex-1 py-2 px-3 text-sm rounded-lg transition ${
                mode === 'save' ? 'bg-indigo-100 text-indigo-700 font-medium' : 'bg-slate-50 text-slate-600 hover:bg-slate-100'
              }`}
            >
              שמור פוסט נוכחי כתבנית
            </button>
          </div>

          {mode === 'list' && (
            <>
              <div className="relative mb-3">
                <Search className="w-4 h-4 absolute right-3 top-1/2 -translate-y-1/2 text-slate-400" />
                <input
                  type="text"
                  placeholder="חיפוש תבנית..."
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  className="w-full pr-9 pl-3 py-2 border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500"
                />
              </div>

              {filteredTemplates.length === 0 ? (
                <div className="text-center py-8 text-slate-500">
                  <FileText className="w-12 h-12 mx-auto mb-2 text-slate-300" />
                  <p className="text-sm">{templates.length === 0 ? 'אין עדיין תבניות' : 'לא נמצאו תבניות'}</p>
                  {templates.length === 0 && (
                    <p className="text-xs mt-1">צור תבנית מתוכן הפוסט הנוכחי בלחיצה על "שמור פוסט"</p>
                  )}
                </div>
              ) : (
                <div className="space-y-2 max-h-96 overflow-y-auto">
                  {filteredTemplates.map(template => (
                    <div key={template.id} className="border border-slate-200 rounded-lg p-3 hover:border-indigo-300 hover:bg-indigo-50/30 transition group">
                      <div className="flex items-start justify-between gap-2 mb-1">
                        <h4 className="font-semibold text-slate-900 text-sm">{template.name}</h4>
                        <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition">
                          <button
                            onClick={() => handleDelete(template.id)}
                            className="p-1 hover:bg-red-50 rounded text-red-500"
                            title="מחק"
                          >
                            <Trash2 className="w-3.5 h-3.5" />
                          </button>
                        </div>
                      </div>
                      {template.title && (
                        <p className="text-xs text-slate-700 font-medium mb-1">{template.title}</p>
                      )}
                      <p className="text-xs text-slate-500 line-clamp-2 mb-2">{stripHtml(template.content)}</p>
                      <button
                        onClick={() => onSelect(template)}
                        className="text-xs text-indigo-600 hover:text-indigo-700 font-medium"
                      >
                        השתמש בתבנית →
                      </button>
                    </div>
                  ))}
                </div>
              )}
            </>
          )}

          {mode === 'save' && (
            <div className="space-y-3">
              {!currentContent.trim() ? (
                <div className="bg-amber-50 border border-amber-200 rounded-lg p-4 flex items-start gap-2">
                  <AlertCircle className="w-4 h-4 text-amber-600 flex-shrink-0 mt-0.5" />
                  <p className="text-sm text-amber-800">
                    אין תוכן לשמור. תחילה כתוב את הפוסט ואז שמור אותו כתבנית.
                  </p>
                </div>
              ) : (
                <>
                  <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1.5">
                      שם התבנית <span className="text-red-500">*</span>
                    </label>
                    <input
                      type="text"
                      value={newTemplateName}
                      onChange={(e) => setNewTemplateName(e.target.value)}
                      placeholder='למשל: "בוקר טוב", "טיפ של היום", "פוסט יום שישי"'
                      className="w-full px-3 py-2 border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500"
                      autoFocus
                    />
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1.5">תצוגה מקדימה</label>
                    <div className="bg-slate-50 border border-slate-200 rounded-lg p-3 max-h-48 overflow-y-auto">
                      {currentTitle && <p className="font-semibold text-slate-900 mb-1">{currentTitle}</p>}
                      <div className="text-sm text-slate-700" dangerouslySetInnerHTML={{ __html: currentContent }} />
                    </div>
                  </div>
                  <button
                    onClick={handleSave}
                    className="w-full py-2.5 bg-indigo-600 hover:bg-indigo-700 text-white text-sm font-medium rounded-lg flex items-center justify-center gap-2"
                  >
                    <Save className="w-4 h-4" />
                    שמור כתבנית
                  </button>
                </>
              )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

// ============== AI ASSISTANT MODAL ==============
function AIAssistantModal({ currentContent, businessName, category, platforms, onApply, onClose }) {
  const [mode, setMode] = useState('improve'); // 'improve', 'generate', 'hashtags', 'shorten'
  const [customPrompt, setCustomPrompt] = useState('');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState('');
  const [error, setError] = useState('');

  const callAI = async (prompt, includeCurrentContent = true) => {
    setLoading(true);
    setError('');
    setResult('');
    
    try {
      const platformsNames = platforms.map(p => PLATFORMS.find(pl => pl.id === p)?.name).filter(Boolean).join(', ');
      const categoryName = POST_CATEGORIES[category]?.label || 'תוכן';
      
      let fullPrompt = `אתה כותב תוכן מקצועי עבור עסק "${businessName}". `;
      fullPrompt += `הפוסט הוא מסוג "${categoryName}" ומיועד לרשתות: ${platformsNames}. `;
      fullPrompt += `עליך להחזיר רק את התוכן הסופי בעברית, ללא הקדמות או הסברים. `;
      
      if (includeCurrentContent && currentContent) {
        fullPrompt += `\n\nהתוכן הנוכחי:\n${stripHtml(currentContent)}\n\n`;
      }
      fullPrompt += `\n${prompt}`;

      // Call Claude API
      const response = await fetch("https://api.anthropic.com/v1/messages", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          model: "claude-sonnet-4-20250514",
          max_tokens: 1000,
          messages: [{ role: "user", content: fullPrompt }],
        })
      });

      if (!response.ok) {
        const errText = await response.text();
        throw new Error('שגיאה בקריאה ל-AI: ' + errText);
      }

      const data = await response.json();
      const text = data.content
        .filter(c => c.type === 'text')
        .map(c => c.text)
        .join('\n');
      
      setResult(text.trim());
    } catch (e) {
      setError(e.message || 'שגיאה לא ידועה');
    } finally {
      setLoading(false);
    }
  };

  const runPreset = (preset) => {
    setMode(preset);
    const prompts = {
      improve: 'שפר את הטקסט הקיים - הפוך אותו ליותר אטרקטיבי, מעניין וקליל. שמור על הרעיון המקורי.',
      shorten: 'קצר את הטקסט לחצי תוך שמירה על המסר העיקרי. תהיה תמציתי וחד.',
      hashtags: 'הצע 8-12 האשטאגים רלוונטיים לפוסט בעברית ובאנגלית. החזר רק את ההאשטאגים מופרדים ברווחים, ללא הסברים.',
      cta: 'הוסף קריאה לפעולה (Call to Action) חזקה בסוף הפוסט. שלב גם אימוג׳ים מתאימים.'
    };
    callAI(prompts[preset]);
  };

  const runCustom = () => {
    if (!customPrompt.trim()) {
      setError('יש להזין הנחיה');
      return;
    }
    callAI(customPrompt);
  };

  const runGenerate = () => {
    if (!customPrompt.trim()) {
      setError('תאר מה תרצה לכתוב');
      return;
    }
    callAI(`כתוב פוסט על: ${customPrompt}`, false);
  };

  return (
    <div className="fixed inset-0 bg-slate-900/50 flex items-end sm:items-center justify-center z-[60] sm:p-4 backdrop-blur-sm" onClick={onClose}>
      <div className="bg-white rounded-t-2xl sm:rounded-2xl max-w-2xl w-full max-h-[95vh] sm:max-h-[85vh] overflow-y-auto" onClick={(e) => e.stopPropagation()}>
        <div className="sticky top-0 bg-white border-b border-slate-200 px-6 py-4 flex items-center justify-between z-10">
          <div className="flex items-center gap-3">
            <div className="w-9 h-9 rounded-xl bg-gradient-to-br from-purple-500 to-pink-500 flex items-center justify-center">
              <Sparkles className="w-4 h-4 text-white" />
            </div>
            <div>
              <h2 className="text-lg font-bold text-slate-900">עוזר AI לכתיבת תוכן</h2>
              <p className="text-xs text-slate-500">מופעל על ידי Claude AI</p>
            </div>
          </div>
          <button onClick={onClose} className="p-1.5 hover:bg-slate-100 rounded-lg">
            <X className="w-5 h-5 text-slate-500" />
          </button>
        </div>

        <div className="p-6 space-y-4">
          {/* Quick actions */}
          <div>
            <label className="block text-sm font-medium text-slate-700 mb-2">פעולות מהירות</label>
            <div className="grid grid-cols-2 gap-2">
              <button
                onClick={() => runPreset('improve')}
                disabled={loading || !currentContent}
                className="py-2.5 px-3 bg-gradient-to-br from-purple-50 to-pink-50 hover:from-purple-100 hover:to-pink-100 border border-purple-200 rounded-lg text-sm font-medium text-purple-700 transition disabled:opacity-50 disabled:cursor-not-allowed text-right"
              >
                ✨ שפר טקסט קיים
              </button>
              <button
                onClick={() => runPreset('shorten')}
                disabled={loading || !currentContent}
                className="py-2.5 px-3 bg-gradient-to-br from-purple-50 to-pink-50 hover:from-purple-100 hover:to-pink-100 border border-purple-200 rounded-lg text-sm font-medium text-purple-700 transition disabled:opacity-50 disabled:cursor-not-allowed text-right"
              >
                ✂️ קצר את הטקסט
              </button>
              <button
                onClick={() => runPreset('hashtags')}
                disabled={loading}
                className="py-2.5 px-3 bg-gradient-to-br from-purple-50 to-pink-50 hover:from-purple-100 hover:to-pink-100 border border-purple-200 rounded-lg text-sm font-medium text-purple-700 transition disabled:opacity-50 text-right"
              >
                #️⃣ הצע האשטאגים
              </button>
              <button
                onClick={() => runPreset('cta')}
                disabled={loading || !currentContent}
                className="py-2.5 px-3 bg-gradient-to-br from-purple-50 to-pink-50 hover:from-purple-100 hover:to-pink-100 border border-purple-200 rounded-lg text-sm font-medium text-purple-700 transition disabled:opacity-50 disabled:cursor-not-allowed text-right"
              >
                🎯 הוסף קריאה לפעולה
              </button>
            </div>
          </div>

          {/* Custom prompt */}
          <div>
            <label className="block text-sm font-medium text-slate-700 mb-1.5">או כתוב הנחיה משלך</label>
            <textarea
              value={customPrompt}
              onChange={(e) => setCustomPrompt(e.target.value)}
              rows={3}
              placeholder='למשל: "כתוב פוסט על השקת מוצר חדש", או "הפוך את הטקסט לפורמלי יותר"'
              className="w-full px-3 py-2 border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-purple-500 resize-none"
            />
            <div className="flex gap-2 mt-2">
              <button
                onClick={runCustom}
                disabled={loading || !customPrompt.trim() || !currentContent}
                className="flex-1 py-2 bg-purple-600 hover:bg-purple-700 disabled:bg-slate-300 text-white text-sm font-medium rounded-lg flex items-center justify-center gap-2"
              >
                <Sparkles className="w-4 h-4" />
                {currentContent ? 'ערוך לפי ההנחיה' : 'אין טקסט לערוך'}
              </button>
              <button
                onClick={runGenerate}
                disabled={loading || !customPrompt.trim()}
                className="flex-1 py-2 bg-pink-600 hover:bg-pink-700 disabled:bg-slate-300 text-white text-sm font-medium rounded-lg flex items-center justify-center gap-2"
              >
                <Plus className="w-4 h-4" />
                צור פוסט חדש
              </button>
            </div>
          </div>

          {/* Loading */}
          {loading && (
            <div className="bg-purple-50 border border-purple-200 rounded-lg p-4 flex items-center gap-3">
              <div className="animate-spin w-5 h-5 border-2 border-purple-600 border-t-transparent rounded-full"></div>
              <p className="text-sm text-purple-700">ה-AI חושב... זה לוקח כמה שניות</p>
            </div>
          )}

          {/* Error */}
          {error && (
            <div className="bg-rose-50 border border-rose-200 rounded-lg p-3 flex items-start gap-2">
              <AlertCircle className="w-4 h-4 text-rose-600 flex-shrink-0 mt-0.5" />
              <div className="text-sm text-rose-800">
                <p className="font-semibold mb-0.5">שגיאה</p>
                <p className="text-xs">{error}</p>
                <p className="text-xs mt-1 opacity-80">ודא שיש API key של Claude מוגדר במערכת. ראה את ה-README להסבר.</p>
              </div>
            </div>
          )}

          {/* Result */}
          {result && !loading && (
            <div className="border-2 border-purple-200 rounded-lg overflow-hidden">
              <div className="bg-purple-50 px-3 py-2 border-b border-purple-200 flex items-center justify-between">
                <span className="text-xs font-semibold text-purple-700 flex items-center gap-1.5">
                  <Sparkles className="w-3 h-3" />
                  תוצאה מ-AI
                </span>
                <button
                  onClick={() => { navigator.clipboard.writeText(result); }}
                  className="text-xs text-purple-600 hover:text-purple-700 font-medium"
                  title="העתק"
                >
                  <Copy className="w-3 h-3 inline" /> העתק
                </button>
              </div>
              <div className="p-3 max-h-64 overflow-y-auto">
                <p className="text-sm text-slate-800 whitespace-pre-wrap">{result}</p>
              </div>
              <div className="px-3 py-2 border-t border-purple-200 bg-purple-50/50 flex gap-2">
                <button
                  onClick={() => onApply(result.replace(/\n/g, '<br>'))}
                  className="flex-1 py-1.5 bg-purple-600 hover:bg-purple-700 text-white text-xs font-medium rounded"
                >
                  ✓ השתמש בתוצאה זו
                </button>
                {currentContent && (
                  <button
                    onClick={() => onApply(currentContent + '<br><br>' + result.replace(/\n/g, '<br>'))}
                    className="flex-1 py-1.5 bg-white border border-purple-300 hover:bg-purple-50 text-purple-700 text-xs font-medium rounded"
                  >
                    + הוסף לסוף הטקסט
                  </button>
                )}
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

// ============== SMART DATE PICKER ==============
function SmartDatePicker({ value, onChange, allPosts, currentPostId, businessName }) {
  const [isOpen, setIsOpen] = useState(false);
  const [viewMonth, setViewMonth] = useState(() => {
    if (value) return new Date(value);
    return new Date();
  });
  const pickerRef = useRef(null);

  const months = ['ינואר', 'פברואר', 'מרץ', 'אפריל', 'מאי', 'יוני', 'יולי', 'אוגוסט', 'ספטמבר', 'אוקטובר', 'נובמבר', 'דצמבר'];
  const dayNames = ['א', 'ב', 'ג', 'ד', 'ה', 'ו', 'ש'];

  // Close on outside click
  useEffect(() => {
    const handleClickOutside = (e) => {
      if (pickerRef.current && !pickerRef.current.contains(e.target)) {
        setIsOpen(false);
      }
    };
    if (isOpen) {
      document.addEventListener('mousedown', handleClickOutside);
      return () => document.removeEventListener('mousedown', handleClickOutside);
    }
  }, [isOpen]);

  const formatDateKey = (d) => {
    const year = d.getFullYear();
    const month = String(d.getMonth() + 1).padStart(2, '0');
    const day = String(d.getDate()).padStart(2, '0');
    return `${year}-${month}-${day}`;
  };

  // Group posts by date - exclude current post being edited
  // ONLY show posts of the current business (so admin doesn't see other clients' posts)
  const postsByDate = allPosts
    .filter(p => p.id !== currentPostId)
    .filter(p => !businessName || p.businessName === businessName)
    .reduce((acc, post) => {
      if (!acc[post.date]) acc[post.date] = [];
      acc[post.date].push(post);
      return acc;
    }, {});

  // Get calendar days
  const getDaysInMonth = (date) => {
    const year = date.getFullYear();
    const month = date.getMonth();
    const firstDay = new Date(year, month, 1);
    const lastDay = new Date(year, month + 1, 0);
    const daysInMonth = lastDay.getDate();
    const startingDayOfWeek = firstDay.getDay();

    const days = [];
    for (let i = 0; i < startingDayOfWeek; i++) days.push(null);
    for (let day = 1; day <= daysInMonth; day++) days.push(new Date(year, month, day));
    return days;
  };

  const days = getDaysInMonth(viewMonth);
  const today = formatDateKey(new Date());
  const selectedDate = value || '';

  const formatDisplay = (dateStr) => {
    if (!dateStr) return 'בחר תאריך';
    const d = new Date(dateStr);
    const dayName = ['ראשון', 'שני', 'שלישי', 'רביעי', 'חמישי', 'שישי', 'שבת'][d.getDay()];
    return `יום ${dayName}, ${d.getDate()}/${d.getMonth() + 1}/${d.getFullYear()}`;
  };

  const selectDate = (date) => {
    onChange(formatDateKey(date));
    setIsOpen(false);
  };

  const changeMonth = (delta) => {
    setViewMonth(new Date(viewMonth.getFullYear(), viewMonth.getMonth() + delta));
  };

  const changeYear = (delta) => {
    setViewMonth(new Date(viewMonth.getFullYear() + delta, viewMonth.getMonth()));
  };

  // Count info for display
  const totalScheduledDays = Object.keys(postsByDate).length;
  // Since postsByDate already filters by current business, any post = same business conflict
  const sameBusinessConflict = (dateKey) => {
    return (postsByDate[dateKey] || []).length > 0;
  };

  return (
    <div className="relative" ref={pickerRef}>
      <button
        type="button"
        onClick={() => setIsOpen(!isOpen)}
        className={`w-full px-3 py-2 border rounded-lg text-right transition flex items-center justify-between gap-2 ${
          isOpen ? 'border-indigo-500 ring-2 ring-indigo-100' : 'border-slate-200 hover:border-slate-300'
        } ${value ? 'text-slate-900' : 'text-slate-400'}`}
      >
        <Calendar className="w-4 h-4 text-slate-400 flex-shrink-0" />
        <span className="flex-1 text-right text-sm truncate">{formatDisplay(value)}</span>
      </button>

      {isOpen && (
        <div className="absolute top-full mt-2 right-0 bg-white border border-slate-200 rounded-xl shadow-xl z-50 p-3" style={{ width: '320px' }}>
          {/* Navigation */}
          <div className="flex items-center justify-between mb-3 px-1">
            <div className="flex items-center gap-1">
              <button
                type="button"
                onClick={() => changeYear(-1)}
                className="p-1 hover:bg-slate-100 rounded text-slate-600 text-xs"
                title="שנה קודמת"
              >
                «
              </button>
              <button
                type="button"
                onClick={() => changeMonth(-1)}
                className="p-1 hover:bg-slate-100 rounded"
                title="חודש קודם"
              >
                <ChevronRight className="w-4 h-4 text-slate-600" />
              </button>
            </div>
            
            <div className="font-semibold text-sm text-slate-900">
              {months[viewMonth.getMonth()]} {viewMonth.getFullYear()}
            </div>
            
            <div className="flex items-center gap-1">
              <button
                type="button"
                onClick={() => changeMonth(1)}
                className="p-1 hover:bg-slate-100 rounded"
                title="חודש הבא"
              >
                <ChevronLeft className="w-4 h-4 text-slate-600" />
              </button>
              <button
                type="button"
                onClick={() => changeYear(1)}
                className="p-1 hover:bg-slate-100 rounded text-slate-600 text-xs"
                title="שנה הבאה"
              >
                »
              </button>
            </div>
          </div>

          {/* Day names */}
          <div className="grid grid-cols-7 mb-1">
            {dayNames.map(day => (
              <div key={day} className="text-center text-xs font-medium text-slate-500 py-1">
                {day}
              </div>
            ))}
          </div>

          {/* Days grid */}
          <div className="grid grid-cols-7 gap-0.5">
            {days.map((day, idx) => {
              if (!day) return <div key={idx}></div>;
              const dateKey = formatDateKey(day);
              const dayPosts = postsByDate[dateKey] || [];
              const postCount = dayPosts.length;
              const isToday = dateKey === today;
              const isSelected = dateKey === selectedDate;
              const hasSameBusiness = sameBusinessConflict(dateKey);
              
              return (
                <button
                  key={idx}
                  type="button"
                  onClick={() => selectDate(day)}
                  className={`relative aspect-square rounded-md text-sm transition flex flex-col items-center justify-center gap-0.5 ${
                    isSelected
                      ? 'bg-indigo-600 text-white font-semibold'
                      : isToday
                      ? 'bg-indigo-50 text-indigo-700 font-semibold hover:bg-indigo-100'
                      : hasSameBusiness
                      ? 'bg-rose-50 text-rose-900 hover:bg-rose-100 ring-1 ring-rose-200'
                      : postCount > 0
                      ? 'bg-amber-50 text-amber-900 hover:bg-amber-100'
                      : 'text-slate-700 hover:bg-slate-100'
                  }`}
                  title={postCount > 0 ? `${postCount} פוסטים מתוזמנים${hasSameBusiness ? ' (כולל ' + businessName + ')' : ''}` : ''}
                >
                  <span>{day.getDate()}</span>
                  {postCount > 0 && !isSelected && (
                    <div className="flex gap-0.5 absolute bottom-0.5">
                      {[...Array(Math.min(postCount, 3))].map((_, i) => (
                        <div 
                          key={i} 
                          className={`w-1 h-1 rounded-full ${
                            hasSameBusiness ? 'bg-rose-500' : 'bg-amber-500'
                          }`}
                        ></div>
                      ))}
                    </div>
                  )}
                </button>
              );
            })}
          </div>

          {/* Legend & info */}
          <div className="mt-3 pt-3 border-t border-slate-100 space-y-1.5">
            {selectedDate && postsByDate[selectedDate] && postsByDate[selectedDate].length > 0 && (
              <div className="bg-rose-50 border border-rose-200 rounded-md p-2">
                <div className="text-xs font-semibold text-rose-900 mb-1 flex items-center gap-1">
                  <AlertCircle className="w-3 h-3" />
                  כבר יש {postsByDate[selectedDate].length} פוסטים של {businessName || 'העסק הזה'} בתאריך זה:
                </div>
                <div className="space-y-0.5">
                  {postsByDate[selectedDate].slice(0, 3).map(p => (
                    <div key={p.id} className="text-xs text-rose-800 flex items-center gap-1.5">
                      <span className="font-mono">{p.time || '--:--'}</span>
                      {p.title && <span className="truncate">· {p.title}</span>}
                    </div>
                  ))}
                  {postsByDate[selectedDate].length > 3 && (
                    <div className="text-xs text-rose-700">+ {postsByDate[selectedDate].length - 3} נוספים</div>
                  )}
                </div>
              </div>
            )}
            
            <div className="flex items-center justify-between text-xs">
              <div className="flex items-center gap-3 text-slate-500">
                {businessName ? (
                  <div className="flex items-center gap-1">
                    <div className="w-1.5 h-1.5 rounded-full bg-rose-500"></div>
                    <span>פוסטים של {businessName}</span>
                  </div>
                ) : (
                  <div className="flex items-center gap-1">
                    <div className="w-1.5 h-1.5 rounded-full bg-amber-500"></div>
                    <span>פוסטים מתוזמנים</span>
                  </div>
                )}
              </div>
              <button
                type="button"
                onClick={() => { selectDate(new Date()); }}
                className="text-xs text-indigo-600 hover:text-indigo-700 font-medium"
              >
                היום
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

// ============== RICH TEXT EDITOR ==============
function RichTextEditor({ value, onChange, placeholder, rows = 5 }) {
  const editorRef = useRef(null);
  const [isFocused, setIsFocused] = useState(false);

  // Set initial content (only once)
  useEffect(() => {
    if (editorRef.current && editorRef.current.innerHTML !== value) {
      editorRef.current.innerHTML = value || '';
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const exec = (command, val = null) => {
    document.execCommand(command, false, val);
    editorRef.current?.focus();
    handleChange();
  };

  const handleChange = () => {
    if (editorRef.current) {
      onChange(editorRef.current.innerHTML);
    }
  };

  const handleLink = () => {
    const url = prompt('הזן כתובת קישור:', 'https://');
    if (url && url !== 'https://') {
      // If there's selected text, wrap it in link; otherwise, insert URL as link
      const selection = window.getSelection();
      if (selection && selection.toString().trim()) {
        exec('createLink', url);
        // Make link open in new tab
        setTimeout(() => {
          const links = editorRef.current?.querySelectorAll('a');
          links?.forEach(link => {
            link.target = '_blank';
            link.rel = 'noopener noreferrer';
          });
          handleChange();
        }, 10);
      } else {
        // Insert URL text and make it a link
        document.execCommand('insertHTML', false, `<a href="${url}" target="_blank" rel="noopener noreferrer">${url}</a>`);
        handleChange();
      }
    }
  };

  const insertEmoji = (emoji) => {
    document.execCommand('insertText', false, emoji);
    handleChange();
  };

  const [showEmoji, setShowEmoji] = useState(false);
  const commonEmojis = ['😊', '😍', '🥰', '😎', '🤩', '🎉', '🎊', '✨', '💫', '⭐', '❤️', '🧡', '💛', '💚', '💙', '💜', '🔥', '💯', '🙌', '👏', '👍', '🎯', '📍', '✅', '☑️', '🎁', '🛍️', '💎', '🌟', '🌈', '☀️', '🌸', '🌺', '🌷', '🌹', '🍀'];

  return (
    <div className={`border rounded-lg overflow-hidden bg-white transition ${isFocused ? 'border-slate-400 ring-2 ring-slate-100' : 'border-slate-200'}`}>
      {/* Toolbar */}
      <div className="flex flex-wrap items-center gap-0.5 px-2 py-1.5 border-b border-slate-200 bg-slate-50">
        <ToolButton onClick={() => exec('bold')} title="מודגש (Ctrl+B)">
          <Bold className="w-4 h-4" />
        </ToolButton>
        <ToolButton onClick={() => exec('italic')} title="נטוי (Ctrl+I)">
          <Italic className="w-4 h-4" />
        </ToolButton>
        <ToolButton onClick={() => exec('underline')} title="קו תחתי (Ctrl+U)">
          <Underline className="w-4 h-4" />
        </ToolButton>
        
        <Divider />
        
        <ToolButton onClick={handleLink} title="הוסף קישור">
          <LinkIcon className="w-4 h-4" />
        </ToolButton>
        
        <Divider />
        
        <ToolButton onClick={() => exec('insertUnorderedList')} title="רשימה">
          <List className="w-4 h-4" />
        </ToolButton>
        <ToolButton onClick={() => exec('insertOrderedList')} title="רשימה ממוספרת">
          <ListOrdered className="w-4 h-4" />
        </ToolButton>
        
        <Divider />
        
        <ToolButton onClick={() => exec('justifyRight')} title="יישור לימין">
          <AlignRight className="w-4 h-4" />
        </ToolButton>
        <ToolButton onClick={() => exec('justifyCenter')} title="מרכז">
          <AlignCenter className="w-4 h-4" />
        </ToolButton>
        <ToolButton onClick={() => exec('justifyLeft')} title="יישור לשמאל">
          <AlignLeft className="w-4 h-4" />
        </ToolButton>
        
        <Divider />
        
        <div className="relative">
          <ToolButton onClick={() => setShowEmoji(!showEmoji)} title="אימוג'י">
            <Smile className="w-4 h-4" />
          </ToolButton>
          {showEmoji && (
            <>
              <div className="fixed inset-0 z-10" onClick={() => setShowEmoji(false)}></div>
              <div className="absolute top-full mt-1 right-0 bg-white border border-slate-200 rounded-lg shadow-lg p-2 grid grid-cols-9 gap-0.5 z-20 w-72">
                {commonEmojis.map(emoji => (
                  <button
                    key={emoji}
                    type="button"
                    onClick={() => { insertEmoji(emoji); setShowEmoji(false); }}
                    className="w-7 h-7 hover:bg-slate-100 rounded text-lg flex items-center justify-center"
                  >
                    {emoji}
                  </button>
                ))}
              </div>
            </>
          )}
        </div>
        
        <ToolButton onClick={() => { document.execCommand('insertText', false, '#'); handleChange(); }} title="הוסף האשטאג">
          <Hash className="w-4 h-4" />
        </ToolButton>
        
        <div className="flex-1"></div>
        
        <button
          type="button"
          onClick={() => exec('removeFormat')}
          className="text-xs text-slate-500 hover:text-slate-700 px-2 py-1 rounded hover:bg-slate-100"
          title="נקה עיצוב"
        >
          נקה עיצוב
        </button>
      </div>

      {/* Editor */}
      <div
        ref={editorRef}
        contentEditable
        onInput={handleChange}
        onFocus={() => setIsFocused(true)}
        onBlur={() => setIsFocused(false)}
        onKeyDown={(e) => {
          // Keep keyboard shortcuts working
          if ((e.ctrlKey || e.metaKey) && ['b', 'i', 'u'].includes(e.key.toLowerCase())) {
            setTimeout(handleChange, 10);
          }
        }}
        className="w-full px-3 py-2.5 focus:outline-none text-slate-900 leading-relaxed"
        style={{ 
          minHeight: `${rows * 1.6}em`,
          direction: 'rtl',
          textAlign: 'right'
        }}
        data-placeholder={placeholder}
        suppressContentEditableWarning
      />
      
      <style>{`
        [contenteditable]:empty:before {
          content: attr(data-placeholder);
          color: #94a3b8;
          pointer-events: none;
        }
        [contenteditable] a {
          color: #2563eb;
          text-decoration: underline;
        }
        [contenteditable] ul, [contenteditable] ol {
          padding-right: 1.5rem;
          margin: 0.25rem 0;
        }
        [contenteditable] b, [contenteditable] strong {
          font-weight: 600;
        }
      `}</style>
    </div>
  );
}

function ToolButton({ onClick, title, children }) {
  return (
    <button
      type="button"
      onClick={onClick}
      title={title}
      className="p-1.5 hover:bg-slate-200 rounded text-slate-700 transition"
    >
      {children}
    </button>
  );
}

function Divider() {
  return <div className="w-px h-5 bg-slate-300 mx-0.5"></div>;
}

function stripHtml(html) {
  if (!html) return '';
  const tmp = document.createElement('div');
  tmp.innerHTML = html;
  return tmp.textContent || tmp.innerText || '';
}

// ============== HELPERS ==============
function formatDateHebrew(dateStr) {
  const date = new Date(dateStr);
  const days = ['ראשון', 'שני', 'שלישי', 'רביעי', 'חמישי', 'שישי', 'שבת'];
  const months = ['ינואר', 'פברואר', 'מרץ', 'אפריל', 'מאי', 'יוני', 'יולי', 'אוגוסט', 'ספטמבר', 'אוקטובר', 'נובמבר', 'דצמבר'];
  return `יום ${days[date.getDay()]}, ${date.getDate()} ב${months[date.getMonth()]} ${date.getFullYear()}`;
}

// ============== NOTIFICATION SYSTEM ==============
// In demo mode (claude.ai), notifications are stored locally for tracking
// In production with PHP backend, this will trigger actual email sends

async function sendNotification(type, data) {
  // Store the notification request in local storage for the demo
  // In production, this should call the PHP backend: POST /api/notifications.php
  try {
    let notifications = [];
    try {
      const existing = await window.storage.get('notification-log');
      if (existing && existing.value) {
        notifications = JSON.parse(existing.value);
      }
    } catch (e) {}
    
    const notification = {
      id: Date.now().toString(),
      type, // 'post_created', 'post_approved', 'post_rejected', 'reminder_48h'
      data,
      timestamp: new Date().toISOString(),
      status: 'pending', // 'pending', 'sent', 'failed'
      message: buildNotificationMessage(type, data)
    };
    
    notifications.push(notification);
    // Keep only last 100 notifications
    if (notifications.length > 100) {
      notifications = notifications.slice(-100);
    }
    
    await window.storage.set('notification-log', JSON.stringify(notifications));
    
    // In production, you would send via your PHP backend:
    // await fetch('/api/notifications.php', { method: 'POST', body: JSON.stringify(notification) });
    
    console.log('[Notification]', type, data);
    return notification;
  } catch (e) {
    console.error('Failed to send notification:', e);
  }
}

function buildNotificationMessage(type, data) {
  switch (type) {
    case 'post_created':
      return {
        to: data.clientEmail,
        subject: `פוסט חדש מחכה לאישורך - ${data.businessName}`,
        body: `שלום ${data.clientName},\n\nפוסט חדש נוסף לגאנט שלך לתאריך ${data.postDate}.\n\nכותרת: ${data.postTitle || 'ללא כותרת'}\n\nאנא היכנס לאשר או להעיר על הפוסט דרך הלינק שקיבלת.`
      };
    case 'post_approved':
      return {
        to: data.adminEmail,
        subject: `${data.clientName} אישר פוסט`,
        body: `הלקוח ${data.clientName} (${data.businessName}) אישר פוסט לתאריך ${data.postDate}.\n\n${data.comment ? 'הערה: ' + data.comment : ''}`
      };
    case 'post_rejected':
      return {
        to: data.adminEmail,
        subject: `${data.clientName} ביקש שינוי בפוסט`,
        body: `הלקוח ${data.clientName} (${data.businessName}) ביקש שינוי בפוסט לתאריך ${data.postDate}.\n\nההערה: ${data.comment}`
      };
    case 'reminder_48h':
      return {
        to: data.clientEmail,
        subject: `תזכורת: פוסטים מחכים לאישורך`,
        body: `שלום ${data.clientName},\n\nיש לך ${data.pendingCount} פוסטים שמחכים לאישורך כבר 48 שעות.\n\nאנא היכנס דרך הלינק שלך לעבור עליהם.`
      };
    default:
      return { to: '', subject: '', body: '' };
  }
}
